Application::Application()
{
    // Initialize the system's core event management
    // Create an event group for inter-task communication
    m_eventGroup = xEventGroupCreate();
    if (m_eventGroup == NULL)
    {
        // Handle error - failed to create event group
        // In embedded systems, this might trigger a system fault or panic
        while(1);
    }

    // Configure AEC (Acoustic Echo Cancellation) mode based on configuration settings
    // Read configuration settings to determine AEC mode
    AecMode_t aecMode = getConfiguredAecMode();

    // Ensure mutual exclusivity between device and server AEC options
    switch(aecMode)
    {
        case AEC_MODE_DISABLED:
            m_aecMode = AEC_MODE_DISABLED;
            break;

        case AEC_MODE_DEVICE_SIDE:
            // Validate that server-side AEC is not also enabled
            if (isServerAecEnabled())
            {
                // Handle conflict - disable server-side AEC
                disableServerAec();
            }
            m_aecMode = AEC_MODE_DEVICE_SIDE;
            break;

        case AEC_MODE_SERVER_SIDE:
            // Validate that device-side AEC is not also enabled
            if (isDeviceAecEnabled())
            {
                // Handle conflict - disable device-side AEC
                disableDeviceAec();
            }
            m_aecMode = AEC_MODE_SERVER_SIDE;
            break;

        default:
            // Handle invalid configuration - default to disabled
            m_aecMode = AEC_MODE_DISABLED;
            break;
    }

