void Run() {
    // Main event loop for the embedded system
    while (true) {
        // Process pending events from various sources
        ProcessSystemEvents();

        // Handle network change events
        if (NetworkStateChanged()) {
            HandleNetworkChange();
        }

        // Process audio commands and voice input
        if (AudioCommandAvailable()) {
            AudioCommand cmd = GetAudioCommand();
            HandleAudioCommand(cmd);
        }

        // Check for state transition requests
        if (StateTransitionRequested()) {
            State newState = GetRequestedState();
            TransitionToState(newState);
        }

        // Handle error conditions and recovery
        if (SystemErrorDetected()) {
            HandleSystemError();
        }

        // Manage chat functionality toggle
        if (ChatToggleRequested()) {
            ToggleChatMode();
        }

        // Update listening state and audio processing
        UpdateListeningState();

        // Process scheduled tasks and periodic operations
        ProcessScheduledTasks();

        // Update device state and UI components
        UpdateDeviceState();
        RefreshUI();

        // Handle timeout and idle monitoring
        if (IdleTimeoutDetected()) {
            EnterIdleMode();
        }

        // Yield processor time to prevent blocking
        YieldProcessor();

        // Small delay to prevent excessive CPU usage
        DelayMicroseconds(1000); // 1ms delay
    }
}

