void HandleToggleChatEvent()
{
    // Check if device is currently speaking
    if (IsDeviceSpeaking())
    {
        // Defer wake word handling until current audio task completes
        SetWakeWordDeferred(true);
        return;
    }

    // Encode the wake word
    std::string encodedWakeWord = EncodeWakeWord();

    // Check if audio channel is open
    if (!IsAudioChannelOpen())
    {
        // Open audio channel for wake word processing
        if (!OpenAudioChannel())
        {
            // Failed to open audio channel, log error and return
            LogError("Failed to open audio channel for wake word processing");
            return;
        }
    }

    // Send wake word data to server
    bool sendSuccess = SendWakeWordToServer(encodedWakeWord);

    if (sendSuccess)
    {
        // Update device listening mode based on acoustic echo cancellation settings
        bool aecEnabled = IsAcousticEchoCancellationEnabled();

        if (aecEnabled)
        {
            // Enable AEC mode for listening
            SetListeningMode(LISTENING_MODE_AEC);
        }
        else
        {
            // Use standard listening mode
            SetListeningMode(LISTENING_MODE_STANDARD);
        }

        // Update device state to indicate wake word detection
        UpdateDeviceState(DEVICE_STATE_WAKE_WORD_DETECTED);

        // Log successful wake word handling
        LogInfo("Wake word processed successfully with AEC: " + std::to_string(aecEnabled));
    }
    else
    {
        // Handle send failure
        LogError("Failed to send wake word to server");
        // Revert to previous listening mode if needed
        RestorePreviousListeningMode();
    }
}

