bool UpgradeFirmware(const std::string& firmwarePath, const std::string& deviceId)
{
    try {
        // Validate input parameters
        if (firmwarePath.empty() || deviceId.empty()) {
            return false;
        }

        // Check if firmware file exists and is valid
        std::ifstream firmwareFile(firmwarePath);
        if (!firmwareFile.is_open()) {
            return false;
        }
        firmwareFile.close();

        // Close any active audio channels to prevent conflicts during upgrade
        // This follows the pattern from SetAecMode which closes active channels
        CloseActiveAudioChannels();

        // Update internal state to indicate firmware upgrade in progress
        UpdateInternalState(FIRMWARE_UPGRADE_IN_PROGRESS, deviceId);

        // Notify UI about firmware upgrade start
        NotifyUINotification(FIRMWARE_UPGRADE_STARTED, deviceId);

        // Perform the actual firmware upgrade process
        bool upgradeSuccess = PerformFirmwareUpgrade(firmwarePath, deviceId);

        if (upgradeSuccess) {
            // Update internal state to success
            UpdateInternalState(FIRMWARE_UPGRADE_SUCCESS, deviceId);

            // Notify UI about successful upgrade
            NotifyUINotification(FIRMWARE_UPGRADE_COMPLETED, deviceId);

            // Reinitialize audio subsystem after successful upgrade
            ReinitializeAudioSubsystem();
        } else {
            // Update internal state to failure
            UpdateInternalState(FIRMWARE_UPGRADE_FAILED, deviceId);

            // Notify UI about failed upgrade
            NotifyUINotification(FIRMWARE_UPGRADE_FAILED, deviceId);
        }

        return upgradeSuccess;
    }
    catch (const std::exception& e) {
        // Handle any exceptions during firmware upgrade
        UpdateInternalState(FIRMWARE_UPGRADE_ERROR, deviceId);
        NotifyUINotification(FIRMWARE_UPGRADE_ERROR, deviceId);
        return false;
    }
}

