bool InitializePartition() {
    // Step 1: Check if assets partition exists in flash memory
    if (!FlashPartitionExists(ASSETS_PARTITION_NAME)) {
        return false;
    }

    // Step 2: Verify partition has sufficient space
    uint32_t partitionSize = GetPartitionSize(ASSETS_PARTITION_NAME);
    if (partitionSize < MIN_ASSETS_PARTITION_SIZE) {
        return false;
    }

    // Step 3: Validate checksum of the partition
    if (!ValidatePartitionChecksum(ASSETS_PARTITION_NAME)) {
        return false;
    }

    // Step 4: Map the partition into memory
    void* partitionMemory = MapPartitionToMemory(ASSETS_PARTITION_NAME);
    if (partitionMemory == nullptr) {
        return false;
    }

    // Step 5: Build index of assets with their sizes and offsets
    AssetIndex* assetIndex = BuildAssetIndex(partitionMemory, partitionSize);
    if (assetIndex == nullptr) {
        UnmapPartitionFromMemory(partitionMemory);
        return false;
    }

    // Step 6: Store the built index for efficient access
    g_assetIndex = assetIndex;
    g_partitionBaseAddress = partitionMemory;
    g_partitionSize = partitionSize;

    // Step 7: Mark partition as initialized and validated
    g_partitionInitialized = true;

    return true;
}

bool Assets::Apply()
{
    // Load the index.json configuration file
    std::ifstream configFile("index.json");
    if (!configFile.is_open()) {
        Logger::Error("Failed to open index.json configuration file");
        return false;
    }

    // Parse JSON configuration
    json config;
    try {
        configFile >> config;
        configFile.close();
    } catch (const std::exception& e) {
        Logger::Error("Failed to parse index.json: " + std::string(e.what()));
        return false;
    }

    // Validate asset version
    if (!config.contains("version")) {
        Logger::Error("Missing version in index.json");
        return false;
    }

    std::string currentVersion = config["version"];
    if (currentVersion != ASSETS_VERSION) {
        Logger::Warning("Asset version mismatch. Expected: " + std::string(ASSETS_VERSION) + 
                       ", Found: " + currentVersion);
        // Continue processing but log warning
    }

    // Apply speech recognition models
    if (config.contains("speech_models")) {
        const auto& speechModels = config["speech_models"];
        for (const auto& model : speechModels) {
            if (!model.contains("name") || !model.contains("path")) {
                Logger::Warning("Invalid speech model configuration");
                continue;
            }

            std::string modelName = model["name"];
            std::string modelPath = model["path"];

            // Load and initialize speech model
            if (!SpeechRecognition::LoadModel(modelName, modelPath)) {
                Logger::Error("Failed to load speech model: " + modelName);
                return false;
            }
        }
    }

    // Apply UI themes
    if (config.contains("ui_themes")) {
        const auto& themes = config["ui_themes"];
        for (const auto& theme : themes) {
            if (!theme.contains("name")) {
                Logger::Warning("Invalid theme configuration - missing name");
                continue;
            }

            std::string themeName = theme["name"];

            // Initialize or update theme subsystem
            if (!ThemeManager::InitializeTheme(themeName)) {
                Logger::Error("Failed to initialize theme: " + themeName);
                return false;
            }

            // Apply fonts if specified
            if (theme.contains("fonts")) {
                const auto& fonts = theme["fonts"];
                for (const auto& font : fonts) {
                    if (!font.contains("name") || !font.contains("path")) {
                        Logger::Warning("Invalid font configuration in theme: " + themeName);
                        continue;
                    }

                    std::string fontName = font["name"];
                    std::string fontPath = font["path"];

                    if (!FontManager::LoadFont(fontName, fontPath)) {
                        Logger::Error("Failed to load font: " + fontName + " for theme: " + themeName);
                        return false;
                    }
                }
            }

            // Apply emojis if specified
            if (theme.contains("emojis")) {
                const auto& emojis = theme["emojis"];
                for (const auto& emoji : emojis) {
                    if (!emoji.contains("name") || !emoji.contains("path")) {
                        Logger::Warning("Invalid emoji configuration in theme: " + themeName);
                        continue;
                    }

                    std::string emojiName = emoji["name"];
                    std::string emojiPath = emoji["path"];

                    if (!EmojiManager::LoadEmoji(emojiName, emojiPath)) {
                        Logger::Error("Failed to load emoji: " + emojiName + " for theme: " + themeName);
                        return false;
                    }
                }
            }
        }
    }

    // Apply any additional asset types here...

    // All assets applied successfully
    Logger::Info("All assets successfully applied");
    return true;
}

Assets::Download(std::string url, std::function<void(int progress, size_t speed)> progressCallback)
{
    // Initialize variables
    int result = 0;
    size_t totalBytesReceived = 0;
    size_t partitionSize = getFlashPartitionSize();
    size_t contentLength = 0;
    size_t lastProgressUpdate = 0;
    auto startTime = std::chrono::steady_clock::now();

    // Step 1: Establish HTTP connection and send GET request
    HTTPClient httpClient;
    result = httpClient.connect(url);
    if (result != HTTP_OK) {
        return false;
    }

    // Step 2: Get content length from response headers
    result = httpClient.getHeader("Content-Length", contentLength);
    if (result != HTTP_OK || contentLength == 0) {
        httpClient.disconnect();
        return false;
    }

    // Step 3: Validate content size against partition size
    if (contentLength > partitionSize) {
        httpClient.disconnect();
        return false;
    }

    // Step 4: Erase flash partition before writing
    result = eraseFlashPartition();
    if (result != FLASH_SUCCESS) {
        httpClient.disconnect();
        return false;
    }

    // Step 5: Prepare for streaming download
    const size_t bufferSize = 1024;
    uint8_t* buffer = new uint8_t[bufferSize];
    size_t bytesWritten = 0;
    bool downloadComplete = false;

    try {
        // Step 6: Start downloading data in chunks
        while (!downloadComplete) {
            size_t bytesRead = 0;
            result = httpClient.read(buffer, bufferSize, bytesRead);

            if (result == HTTP_ERROR) {
                delete[] buffer;
                httpClient.disconnect();
                return false;
            }

            if (bytesRead == 0) {
                // End of stream
                downloadComplete = true;
                break;
            }

            // Step 7: Write data to flash memory
            result = writeFlash(bytesWritten, buffer, bytesRead);
            if (result != FLASH_SUCCESS) {
                delete[] buffer;
                httpClient.disconnect();
                return false;
            }

            bytesWritten += bytesRead;
            totalBytesReceived += bytesRead;

            // Step 8: Calculate and report progress
            if (totalBytesReceived - lastProgressUpdate >= 1024 || downloadComplete) {
                int progressPercent = (int)((double)totalBytesReceived / contentLength * 100);
                auto currentTime = std::chrono::steady_clock::now();
                auto duration = std::chrono::duration_cast<std::chrono::milliseconds>(
                    currentTime - startTime).count();

                size_t speed = (duration > 0) ? (totalBytesReceived * 1000 / duration) : 0;

                if (progressCallback) {
                    progressCallback(progressPercent, speed);
                }

                lastProgressUpdate = totalBytesReceived;
            }
        }

        // Step 9: Verify download completion
        if (bytesWritten != contentLength) {
            delete[] buffer;
            httpClient.disconnect();
            return false;
        }

        // Step 10: Finalize flash operations
        result = finalizeFlashWrite();
        if (result != FLASH_SUCCESS) {
            delete[] buffer;
            httpClient.disconnect();
            return false;
        }

        delete[] buffer;
        httpClient.disconnect();
        return true;

    } catch (...) {
        // Cleanup on exception
        delete[] buffer;
        httpClient.disconnect();
        return false;
    }
}

bool IsValidTransition(DeviceState currentState, DeviceState targetState) const
{
    // Self-transitions are generally not allowed unless explicitly permitted
    if (currentState == targetState)
    {
        return false;
    }

    // Define valid state transitions based on common embedded system patterns
    switch (currentState)
    {
        case DEVICE_STATE_POWER_OFF:
            // Can only transition to POWER_ON from POWER_OFF
            return (targetState == DEVICE_STATE_POWER_ON);

        case DEVICE_STATE_POWER_ON:
            // Can transition to INITIALIZATION after power on
            return (targetState == DEVICE_STATE_INITIALIZATION);

        case DEVICE_STATE_INITIALIZATION:
            // Can transition to OPERATIONAL or ERROR after initialization
            return ((targetState == DEVICE_STATE_OPERATIONAL) || 
                    (targetState == DEVICE_STATE_ERROR));

        case DEVICE_STATE_OPERATIONAL:
            // Can transition to STANDBY or ERROR from operational
            return ((targetState == DEVICE_STATE_STANDBY) || 
                    (targetState == DEVICE_STATE_ERROR));

        case DEVICE_STATE_STANDBY:
            // Can transition back to OPERATIONAL or POWER_OFF
            return ((targetState == DEVICE_STATE_OPERATIONAL) || 
                    (targetState == DEVICE_STATE_POWER_OFF));

        case DEVICE_STATE_ERROR:
            // Can only transition back to INITIALIZATION or POWER_OFF from ERROR
            return ((targetState == DEVICE_STATE_INITIALIZATION) || 
                    (targetState == DEVICE_STATE_POWER_OFF));

        default:
            // Unknown state - invalid transition
            return false;
    }
}

bool DeviceStateMachine::TransitionTo(DeviceState newState)
{
    // Validate that the new state is a valid device state
    if (newState < 0 || newState >= DEVICE_STATE_COUNT)
    {
        return false;
    }

    // Check if the transition is allowed from current state to new state
    // This assumes we have a transition matrix or rules table
    if (!IsTransitionAllowed(m_currentState, newState))
    {
        return false;
    }

    // Store the previous state for observer notification
    DeviceState previousState = m_currentState;

    // Perform the actual state transition
    m_currentState = newState;

    // Notify all registered observers about the state change
    NotifyObservers(previousState, newState);

    // Optional: Add any state-specific actions here
    switch (newState)
    {
        case DEVICE_STATE_IDLE:
            // Perform idle-specific initialization
            break;
        case DEVICE_STATE_ACTIVE:
            // Perform active-specific setup
            break;
        case DEVICE_STATE_ERROR:
            // Handle error state specific actions
            break;
        default:
            // Handle other states if needed
            break;
    }

    return true;
}

