void McpServer::AddUserOnlyTools()
{
    // Register system information retrieval tool
    mcpServer->RegisterTool("get_system_info", [this](const std::string& params) -> std::string {
        try {
            // Retrieve system information
            SystemInfo info = GetSystemInfo();
            nlohmann::json response;
            response["system_name"] = info.systemName;
            response["version"] = info.version;
            response["uptime"] = info.uptime;
            response["memory_usage"] = info.memoryUsage;
            response["cpu_usage"] = info.cpuUsage;
            return response.dump();
        } catch (const std::exception& e) {
            return "{\"error\": \"Failed to retrieve system information\"}";
        }
    });

    // Register device reboot tool
    mcpServer->RegisterTool("reboot_device", [this](const std::string& params) -> std::string {
        try {
            // Schedule reboot operation in the application's event loop for safety
            appEventLoop->Post([this]() {
                // Perform safe reboot operation
                if (SafeReboot()) {
                    // Reboot is scheduled, return success
                    return "{\"status\": \"reboot_scheduled\"}";
                } else {
                    return "{\"error\": \"Failed to schedule reboot\"}";
                }
            });
            return "{\"status\": \"reboot_scheduled\"}";
        } catch (const std::exception& e) {
            return "{\"error\": \"Failed to initiate reboot\"}";
        }
    });

    // Register firmware upgrade tool
    mcpServer->RegisterTool("upgrade_firmware", [this](const std::string& params) -> std::string {
        try {
            nlohmann::json paramJson = nlohmann::json::parse(params);
            std::string firmwareUrl = paramJson.value("url", "");

            if (firmwareUrl.empty()) {
                return "{\"error\": \"Firmware URL is required\"}";
            }

            // Validate firmware URL format
            if (!IsValidUrl(firmwareUrl)) {
                return "{\"error\": \"Invalid firmware URL format\"}";
            }

            // Schedule firmware upgrade in the application's event loop for safety
            appEventLoop->Post([this, firmwareUrl]() {
                // Perform safe firmware upgrade operation
                if (SafeFirmwareUpgrade(firmwareUrl)) {
                    return "{\"status\": \"firmware_upgrade_started\"}";
                } else {
                    return "{\"error\": \"Failed to start firmware upgrade\"}";
                }
            });

            return "{\"status\": \"firmware_upgrade_started\"}";
        } catch (const nlohmann::json::exception& e) {
            return "{\"error\": \"Invalid parameters for firmware upgrade\"}";
        } catch (const std::exception& e) {
            return "{\"error\": \"Failed to initiate firmware upgrade\"}";
        }
    });

    // Register screen snapshot tool
    mcpServer->RegisterTool("capture_snapshot", [this](const std::string& params) -> std::string {
        try {
            // Capture screen snapshot
            std::string snapshotData = CaptureScreenSnapshot();

            // Encode snapshot data to base64 for transmission
            std::string encodedData = Base64Encode(snapshotData);

            nlohmann::json response;
            response["snapshot_data"] = encodedData;
            response["timestamp"] = GetCurrentTimestamp();
            return response.dump();
        } catch (const std::exception& e) {
            return "{\"error\": \"Failed to capture screen snapshot\"}";
        }
    });
}

void McpServer::ParseMessage(const cJSON *message)
{
    // Validate input message
    if (!message) {
        SendError(-32600, "Invalid request", nullptr);
        return;
    }

    // Parse JSON-RPC version
    const cJSON *jsonrpc = cJSON_GetObjectItem(message, "jsonrpc");
    if (!jsonrpc || !cJSON_IsString(jsonrpc) || strcmp(jsonrpc->valuestring, "2.0") != 0) {
        SendError(-32600, "Invalid request", nullptr);
        return;
    }

    // Parse method
    const cJSON *method = cJSON_GetObjectItem(message, "method");
    if (!method || !cJSON_IsString(method)) {
        SendError(-32600, "Invalid request", nullptr);
        return;
    }

    // Parse ID (optional for notifications)
    const cJSON *id = cJSON_GetObjectItem(message, "id");

    // Parse params (optional)
    const cJSON *params = cJSON_GetObjectItem(message, "params");

    // Route to appropriate handler based on method
    const char *methodStr = method->valuestring;

    if (strcmp(methodStr, "initialize") == 0) {
        HandleInitialize(params, id);
    }
    else if (strcmp(methodStr, "tools/list") == 0) {
        HandleToolsList(params, id);
    }
    else if (strcmp(methodStr, "tools/call") == 0) {
        HandleToolsCall(params, id);
    }
    else {
        // Unknown method
        SendError(-32601, "Method not found", id);
        return;
    }
}

void McpServer::HandleInitialize(const cJSON *params, const cJSON *id)
{
    // Validate parameters for initialize
    if (params && !cJSON_IsObject(params)) {
        SendError(-32602, "Invalid params", id);
        return;
    }

    // Extract capabilities from params if present
    const cJSON *capabilities = cJSON_GetObjectItem(params, "capabilities");

    // Parse capabilities if provided
    if (capabilities && cJSON_IsObject(capabilities)) {
        // Process capabilities here
        // This is where we would parse and store capability information
        ParseCapabilities(capabilities);
    }

    // Create and send response
    cJSON *response = cJSON_CreateObject();
    cJSON_AddStringToObject(response, "jsonrpc", "2.0");
    cJSON_AddItemToObject(response, "id", cJSON_Duplicate(id, 1));

    // Create result object with server capabilities
    cJSON *result = cJSON_CreateObject();
    cJSON_AddStringToObject(result, "name", "MCP Server");
    cJSON_AddStringToObject(result, "version", "1.0.0");

    // Add server capabilities if available
    cJSON *serverCapabilities = cJSON_CreateObject();
    cJSON_AddItemToObject(serverCapabilities, "tools", cJSON_CreateTrue());
    cJSON_AddItemToObject(result, "capabilities", serverCapabilities);

    cJSON_AddItemToObject(response, "result", result);

    // Send response
    SendResponse(response);
    cJSON_Delete(response);
}

void McpServer::HandleToolsList(const cJSON *params, const cJSON *id)
{
    // Validate parameters for tools/list
    if (params && !cJSON_IsObject(params)) {
        SendError(-32602, "Invalid params", id);
        return;
    }

    // Get optional filter parameters
    const cJSON *filter = cJSON_GetObjectItem(params, "filter");

    // Create tools list
    cJSON *toolsArray = cJSON_CreateArray();

    // Add all registered tools to the list
    for (const auto& tool : registeredTools) {
        cJSON *toolObj = cJSON_CreateObject();
        cJSON_AddStringToObject(toolObj, "name", tool.name.c_str());
        cJSON_AddStringToObject(toolObj, "description", tool.description.c_str());

        // Add parameters if they exist
        if (!tool.parameters.empty()) {
            cJSON *paramsObj = cJSON_CreateObject();
            for (const auto& param : tool.parameters) {
                cJSON_AddStringToObject(paramsObj, param.first.c_str(), param.second.c_str());
            }
            cJSON_AddItemToObject(toolObj, "parameters", paramsObj);
        }

        cJSON_AddItemToArray(toolsArray, toolObj);
    }

    // Create response
    cJSON *response = cJSON_CreateObject();
    cJSON_AddStringToObject(response, "jsonrpc", "2.0");
    cJSON_AddItemToObject(response, "id", cJSON_Duplicate(id, 1));

    cJSON *result = cJSON_CreateObject();
    cJSON_AddItemToObject(result, "tools", toolsArray);
    cJSON_AddItemToObject(response, "result", result);

    SendResponse(response);
    cJSON_Delete(response);
}

void McpServer::HandleToolsCall(const cJSON *params, const cJSON *id)
{
    // Validate parameters for tools/call
    if (!params || !cJSON_IsObject(params)) {
        SendError(-32602, "Invalid params", id);
        return;
    }

    // Parse required parameters
    const cJSON *toolName = cJSON_GetObjectItem(params, "tool");
    const cJSON *arguments = cJSON_GetObjectItem(params, "arguments");

    if (!toolName || !cJSON_IsString(toolName)) {
        SendError(-32602, "Missing tool name", id);
        return;
    }

    // Find the requested tool
    std::string toolNameStr = toolName->valuestring;
    Tool* targetTool = nullptr;

    for (auto& tool : registeredTools) {
        if (tool.name == toolNameStr) {
            targetTool = &tool;
            break;
        }
    }

    if (!targetTool) {
        SendError(-32601, "Tool not found", id);
        return;
    }

    // Validate arguments against tool parameters
    if (arguments && cJSON_IsObject(arguments)) {
        // Check if arguments match expected parameters
        for (const auto& param : targetTool->parameters) {
            const cJSON *argValue = cJSON_GetObjectItem(arguments, param.first.c_str());
            if (!argValue) {
                // Missing required argument
                SendError(-32602, ("Missing required argument: " + param.first).c_str(), id);
                return;
            }
        }
    }

    // Execute the tool
    try {
        std::string result = targetTool->execute(arguments);

        // Create successful response
        cJSON *response = cJSON_CreateObject();
        cJSON_AddStringToObject(response, "jsonrpc", "2.0");
        cJSON_AddItemToObject(response, "id", cJSON_Duplicate(id, 1));

        cJSON *resultObj = cJSON_CreateObject();
        cJSON_AddStringToObject(resultObj, "content", result.c_str());
        cJSON_AddItemToObject(response, "result", resultObj);

        SendResponse(response);
        cJSON_Delete(response);
    }
    catch (const std::exception& e) {
        SendError(-32000, ("Tool execution failed: " + std::string(e.what())).c_str(), id);
    }
}

