void McpServer::SendError(int errorCode, const char* errorMessage, const cJSON *id)
{
    // Create error response
    cJSON *errorResponse = cJSON_CreateObject();
    cJSON_AddStringToObject(errorResponse, "jsonrpc", "2.0");

    if (id) {
        cJSON_AddItemToObject(errorResponse, "id", cJSON_Duplicate(id, 1));
    } else {
        cJSON_AddNullToObject(errorResponse, "id");
    }

    cJSON *errorObj = cJSON_CreateObject();
    cJSON_AddNumberToObject(errorObj, "code", errorCode);
    cJSON_AddStringToObject(errorObj, "message", errorMessage);
    cJSON_AddItemToObject(errorResponse, "error", errorObj);

    SendResponse(errorResponse);
    cJSON_Delete(errorResponse);
}

