Json::Value GetToolsList(int pageSize, const std::string& cursor, bool includeDisabled) {
    Json::Value response(Json::objectValue);
    Json::Value toolsArray(Json::arrayValue);

    try {
        // Validate input parameters
        if (pageSize <= 0 || pageSize > 1000) {  // Assuming max page size of 1000
            response["error"] = "Invalid page size. Must be between 1 and 1000.";
            response["success"] = false;
            return response;
        }

        // Fetch tools from MCP server with pagination
        std::vector<Tool> rawTools = mcpClient.fetchToolsFromServer(cursor, pageSize + 1);  // Fetch one extra to determine if there's more

        int processedCount = 0;
        int maxPayloadSize = 1024 * 1024;  // 1MB limit for demonstration

        // Process tools and apply filters
        for (const auto& tool : rawTools) {
            // Check if we've reached the requested page size
            if (processedCount >= pageSize) {
                break;
            }

            // Apply permission filter
            if (!tool.hasPermission) {
                continue;
            }

            // Apply disabled filter
            if (!includeDisabled && tool.name.empty()) {  // Assuming empty name means disabled
                continue;
            }

            // Check payload size constraint
            if (tool.payload.length() > maxPayloadSize) {
                response["error"] = "Tool '" + tool.name + "' exceeds maximum payload size limit";
                response["success"] = false;
                return response;
            }

            // Add tool to response
            Json::Value toolJson(Json::objectValue);
            toolJson["id"] = tool.id;
            toolJson["name"] = tool.name;
            toolJson["description"] = tool.description;

            toolsArray.append(toolJson);
            processedCount++;
        }

        // Determine if there are more results
        bool hasNext = (rawTools.size() > pageSize);
        std::string nextCursor = hasNext ? "cursor_" + std::to_string(pageSize) : "";

        // Build final response
        response["tools"] = toolsArray;
        response["hasNext"] = hasNext;
        response["nextCursor"] = nextCursor;
        response["totalCount"] = processedCount;
        response["success"] = true;

    } catch (const std::exception& e) {
        response["error"] = "Internal error: " + std::string(e.what());
        response["success"] = false;
    } catch (...) {
        response["error"] = "Unknown internal error occurred";
        response["success"] = false;
    }

    return response;
}

bool McpServer::DoToolCall(int clientId, const std::string& toolName, const cJSON* args)
{
    // Validate input parameters
    if (toolName.empty()) {
        SendError(clientId, "Invalid tool name: empty string");
        return false;
    }

    if (!args) {
        SendError(clientId, "Invalid arguments: null pointer");
        return false;
    }

    // Find the registered tool by name
    auto toolIt = registeredTools.find(toolName);
    if (toolIt == registeredTools.end()) {
        SendError(clientId, "Unknown tool: " + toolName);
        return false;
    }

    const ToolInfo& toolInfo = toolIt->second;

    // Parse and validate arguments
    std::map<std::string, std::string> parsedArgs;
    std::vector<std::string> missingRequiredArgs;

    // Check all required parameters
    for (const auto& param : toolInfo.parameters) {
        if (param.required && !cJSON_HasObjectItem(args, param.name.c_str())) {
            missingRequiredArgs.push_back(param.name);
        }
    }

    if (!missingRequiredArgs.empty()) {
        std::string errorMsg = "Missing required arguments: ";
        for (size_t i = 0; i < missingRequiredArgs.size(); ++i) {
            if (i > 0) errorMsg += ", ";
            errorMsg += missingRequiredArgs[i];
        }
        SendError(clientId, errorMsg);
        return false;
    }

    // Parse all provided arguments
    cJSON* argItem = args->child;
    while (argItem) {
        const char* argName = argItem->string;
        if (argName) {
            // Validate argument name exists in tool definition
            bool isValidParam = false;
            for (const auto& param : toolInfo.parameters) {
                if (param.name == argName) {
                    isValidParam = true;
                    break;
                }
            }

            if (!isValidParam) {
                SendError(clientId, "Unknown parameter: " + std::string(argName));
                return false;
            }

            // Parse argument value based on expected type
            std::string valueStr;
            switch (argItem->type) {
                case cJSON_String:
                    valueStr = argItem->valuestring ? argItem->valuestring : "";
                    break;
                case cJSON_Number:
                    valueStr = std::to_string(argItem->valuedouble);
                    break;
                case cJSON_True:
                    valueStr = "true";
                    break;
                case cJSON_False:
                    valueStr = "false";
                    break;
                case cJSON_NULL:
                    valueStr = "null";
                    break;
                default:
                    valueStr = "";
                    break;
            }

            parsedArgs[argName] = valueStr;
        }
        argItem = argItem->next;
    }

    // Create tool execution context
    ToolExecutionContext context;
    context.clientId = clientId;
    context.toolName = toolName;
    context.arguments = parsedArgs;
    context.timestamp = std::chrono::steady_clock::now();

    // Schedule tool execution on main thread
    try {
        // Submit task to main thread executor
        mainThreadExecutor.Submit([this, context]() {
            ExecuteTool(context);
        });

        return true;
    } catch (const std::exception& e) {
        SendError(context.clientId, "Failed to schedule tool execution: " + std::string(e.what()));
        return false;
    }
}

private:
void McpServer::ExecuteTool(const ToolExecutionContext& context)
{
    try {
        // Find the registered tool
        auto toolIt = registeredTools.find(context.toolName);
        if (toolIt == registeredTools.end()) {
            SendError(context.clientId, "Tool not found during execution: " + context.toolName);
            return;
        }

        const ToolInfo& toolInfo = toolIt->second;

        // Execute the tool with validated arguments
        ToolResult result = toolInfo.executeCallback(context.arguments);

        // Send successful result back to client
        if (result.success) {
            SendToolResult(context.clientId, context.toolName, result.data);
        } else {
            SendError(context.clientId, result.error);
        }
    } catch (const std::exception& e) {
        SendError(context.clientId, "Tool execution failed: " + std::string(e.what()));
    }
}

int Ota::CheckVersion()
{
    // Initialize variables
    int result = 0;
    bool updateAvailable = false;
    std::string response;
    Json::Value root;

    // Send HTTP request to firmware update server
    result = SendHttpRequest("GET", "/firmware/version", response);
    if (result != 0)
    {
        return OTA_ERROR_HTTP_REQUEST_FAILED;
    }

    // Parse JSON response
    Json::CharReaderBuilder readerBuilder;
    Json::String errs;

    if (!Json::parseFromStream(readerBuilder, response, &root, &errs))
    {
        return OTA_ERROR_JSON_PARSE_FAILED;
    }

    // Extract version information from JSON response
    std::string latestVersion = root["version"].asString();
    std::string downloadUrl = root["download_url"].asString();
    std::string releaseNotes = root["release_notes"].asString();

    // Compare current version with latest version
    if (CompareVersions(currentFirmwareVersion, latestVersion) < 0)
    {
        updateAvailable = true;
    }

    // If update is available, proceed with update process
    if (updateAvailable)
    {
        // Store update information
        pendingUpdate.version = latestVersion;
        pendingUpdate.downloadUrl = downloadUrl;
        pendingUpdate.releaseNotes = releaseNotes;

        // Check for activation data in response
        if (root.isMember("activation_data"))
        {
            Json::Value activationData = root["activation_data"];

            // Process activation related data
            std::string activationKey = activationData["key"].asString();
            std::string activationValue = activationData["value"].asString();

            // Store activation data for later use
            activationDataMap[activationKey] = activationValue;
        }

        // Check for MQTT configuration updates
        if (root.isMember("mqtt_config"))
        {
            Json::Value mqttConfig = root["mqtt_config"];

            // Update MQTT configuration parameters
            mqttBrokerAddress = mqttConfig["broker_address"].asString();
            mqttBrokerPort = mqttConfig["broker_port"].asInt();
            mqttClientId = mqttConfig["client_id"].asString();

            // Update MQTT credentials if present
            if (mqttConfig.isMember("username"))
            {
                mqttUsername = mqttConfig["username"].asString();
            }

            if (mqttConfig.isMember("password"))
            {
                mqttPassword = mqttConfig["password"].asString();
            }

            // Notify MQTT subsystem about configuration changes
            NotifyMqttConfigChanged();
        }

        // Log the update availability
        LogInfo("New firmware version %s is available for download", latestVersion.c_str());

        // Set update flag
        firmwareUpdatePending = true;
    }
    else
    {
        // No update available
        LogInfo("Current firmware version %s is up to date", currentFirmwareVersion.c_str());
    }

    // Return success
    return OTA_SUCCESS;
}

