namespace Ota {
    class Upgrade {
    public:
        void Upgrade(const std::string& url, std::function<void(int progress, size_t speed)> progressCallback) {
            try {
                // Step 1: Initialize download process
                std::cout << "Starting firmware upgrade from: " << url << std::endl;

                // Simulate network connection and authentication
                std::this_thread::sleep_for(std::chrono::milliseconds(500));

                // Step 2: Download firmware image (simulated)
                const size_t totalSize = 1024 * 1024; // 1MB simulated firmware size
                size_t downloadedBytes = 0;
                const size_t chunkSize = 1024; // 1KB chunks

                auto startTime = std::chrono::high_resolution_clock::now();

                // Simulate download progress
                while (downloadedBytes < totalSize) {
                    // Simulate downloading a chunk
                    std::this_thread::sleep_for(std::chrono::milliseconds(10));

                    downloadedBytes += chunkSize;
                    if (downloadedBytes > totalSize) {
                        downloadedBytes = totalSize;
                    }

                    // Calculate progress percentage
                    int progress = (int)((downloadedBytes * 100) / totalSize);

                    // Calculate speed (bytes per second)
                    auto currentTime = std::chrono::high_resolution_clock::now();
                    auto duration = std::chrono::duration_cast<std::chrono::seconds>(currentTime - startTime).count();
                    size_t speed = (duration > 0) ? (downloadedBytes / duration) : downloadedBytes;

                    // Report progress and speed
                    if (progressCallback) {
                        progressCallback(progress, speed);
                    }

                    // Print progress for debugging
                    if (progress % 10 == 0) {
                        std::cout << "Download progress: " << progress << "% (" 
                                  << downloadedBytes << "/" << totalSize << " bytes)" << std::endl;
                    }
                }

                // Step 3: Verify firmware header integrity
                std::cout << "Verifying firmware header integrity..." << std::endl;
                std::this_thread::sleep_for(std::chrono::milliseconds(300));

                // Simulate header verification (in real implementation, this would check CRC/checksum)
                bool headerValid = true;
                if (!headerValid) {
                    throw std::runtime_error("Firmware header verification failed");
                }

                // Step 4: Check version compatibility
                std::cout << "Checking version compatibility..." << std::endl;
                std::this_thread::sleep_for(std::chrono::milliseconds(200));

                // Simulate version checking (in real implementation, this would compare versions)
                bool versionCompatible = true;
                if (!versionCompatible) {
                    throw std::runtime_error("New firmware version is not compatible with current system");
                }

                // Step 5: Write firmware to OTA partition (simulated)
                std::cout << "Writing firmware to OTA partition..." << std::endl;
                const size_t writeSize = totalSize;
                size_t writtenBytes = 0;

                while (writtenBytes < writeSize) {
                    std::this_thread::sleep_for(std::chrono::milliseconds(5));
                    writtenBytes += chunkSize;
                    if (writtenBytes > writeSize) {
                        writtenBytes = writeSize;
                    }

                    int writeProgress = (int)((writtenBytes * 100) / writeSize);
                    if (writeProgress % 10 == 0) {
                        std::cout << "Write progress: " << writeProgress << "%" << std::endl;
                    }
                }

                // Step 6: Final verification
                std::cout << "Performing final firmware verification..." << std::endl;
                std::this_thread::sleep_for(std::chrono::milliseconds(500));

                // Simulate final verification
                bool finalVerification = true;
                if (!finalVerification) {
                    throw std::runtime_error("Final firmware verification failed");
                }

                std::cout << "Firmware upgrade completed successfully!" << std::endl;
                std::cout << "Please reboot the device to apply the new firmware." << std::endl;

            } catch (const std::exception& e) {
                std::cerr << "Firmware upgrade failed: " << e.what() << std::endl;
                throw; // Re-throw the exception for error handling upstream
            }
        }
    };
}

std::string Ota::GetActivationPayload() {
    // Check if device serial number is available
    std::string serialNumber = GetDeviceSerialNumber();
    if (serialNumber.empty()) {
        return "{}";
    }

    // Generate challenge string (this could be random or derived from system)
    std::string challenge = GenerateChallengeString();

    // Create the payload structure
    Json::Value payload;
    payload["serialNumber"] = serialNumber;
    payload["challenge"] = challenge;

    // Convert payload to string for signing
    Json::StreamWriterBuilder builder;
    builder["indentation"] = "";
    std::string payloadStr = Json::writeString(builder, payload);

    // Generate HMAC-SHA256 signature using hardware-backed key
    std::string signature = GenerateHmacSignature(payloadStr);

    // Add signature to payload
    payload["signature"] = signature;

    // Return final JSON string
    return Json::writeString(builder, payload);
}

int Ota::Activate()
{
    // Initialize variables
    int httpStatus = 0;
    int result = 0;

    // Construct activation URL - typically includes device ID and update information
    std::string activationUrl = "https://ota-server.com/activate";

    // Prepare payload data (JSON format)
    std::string payload = "{";
    payload += "\"deviceId\":\"" + GetDeviceId() + "\",";
    payload += "\"firmwareVersion\":\"" + GetCurrentFirmwareVersion() + "\",";
    payload += "\"activationTime\":" + std::to_string(GetCurrentTimestamp());
    payload += "}";

    // Set up HTTP headers
    std::map<std::string, std::string> headers;
    headers["Content-Type"] = "application/json";
    headers["Content-Length"] = std::to_string(payload.length());

    // Send HTTP POST request
    try {
        // In embedded systems, this would typically use a HTTP client library
        // For example: HttpClient::Post(activationUrl, payload, headers, &httpStatus);

        // Simulate HTTP communication (actual implementation would use network stack)
        result = SendHttpRequest(activationUrl, payload, headers, &httpStatus);

        if (result != 0) {
            return OTA_ERROR_NETWORK_FAILED;
        }

        // Handle different HTTP status codes
        switch (httpStatus) {
            case 200: // Success
                return OTA_SUCCESS;
            case 400: // Bad Request
                return OTA_ERROR_INVALID_REQUEST;
            case 401: // Unauthorized
                return OTA_ERROR_UNAUTHORIZED;
            case 404: // Not Found
                return OTA_ERROR_NOT_FOUND;
            case 500: // Internal Server Error
                return OTA_ERROR_SERVER_ERROR;
            case 503: // Service Unavailable
                return OTA_ERROR_SERVICE_UNAVAILABLE;
            default:
                // Handle other error cases
                if (httpStatus >= 400) {
                    return OTA_ERROR_HTTP_FAILURE;
                } else {
                    return OTA_ERROR_UNKNOWN;
                }
        }
    }
    catch (const std::exception& e) {
        // Handle exceptions that might occur during network operations
        return OTA_ERROR_EXCEPTION;
    }

    return OTA_ERROR_UNKNOWN;
}

void PrintTaskCpuUsage(TickType_t delayTicks)
{
    // Array to store task statistics before and after measurement
    TaskStatus_t *pxTaskStatusArrayBefore;
    TaskStatus_t *pxTaskStatusArrayAfter;
    UBaseType_t uxArraySize;
    uint32_t ulTotalRunTimeBefore = 0;
    uint32_t ulTotalRunTimeAfter = 0;
    uint32_t ulRunTimeDiff;
    float flPercentage;
    TaskHandle_t xCreatedTasks[configMAX_TASKS];
    TaskHandle_t xDeletedTasks[configMAX_TASKS];
    UBaseType_t uxCreatedCount = 0;
    UBaseType_t uxDeletedCount = 0;
    TaskHandle_t xTask;
    TaskStatus_t xTaskStatus;

    // Get the number of tasks in the system
    uxArraySize = uxTaskGetNumberOfTasks();

    // Allocate memory for task status arrays
    pxTaskStatusArrayBefore = (TaskStatus_t *)pvPortMalloc(uxArraySize * sizeof(TaskStatus_t));
    pxTaskStatusArrayAfter = (TaskStatus_t *)pvPortMalloc(uxArraySize * sizeof(TaskStatus_t));

    if ((pxTaskStatusArrayBefore == NULL) || (pxTaskStatusArrayAfter == NULL))
    {
        // Memory allocation failed, free what we can and return
        if (pxTaskStatusArrayBefore != NULL)
            vPortFree(pxTaskStatusArrayBefore);
        if (pxTaskStatusArrayAfter != NULL)
            vPortFree(pxTaskStatusArrayAfter);
        return;
    }

    // Get current task information before delay
    uxArraySize = uxTaskGetSystemState(pxTaskStatusArrayBefore, uxArraySize, &ulTotalRunTimeBefore);

    // Wait for the specified delay period
    vTaskDelay(delayTicks);

    // Get current task information after delay
    uxArraySize = uxTaskGetSystemState(pxTaskStatusArrayAfter, uxArraySize, &ulTotalRunTimeAfter);

    // Calculate total run time difference
    if (ulTotalRunTimeAfter > ulTotalRunTimeBefore)
    {
        ulRunTimeDiff = ulTotalRunTimeAfter - ulTotalRunTimeBefore;
    }
    else
    {
        ulRunTimeDiff = 0; // Handle potential wraparound
    }

    // Print header
    printf("Task CPU Usage Report (over %lu ticks):\n", delayTicks);
    printf("=========================================\n");
    printf("%-20s %-15s %-10s %-10s\n", "Task Name", "Task State", "CPU %", "Stack Free");
    printf("-----------------------------------------\n");

    // Process each task and calculate CPU usage
    for (UBaseType_t i = 0; i < uxArraySize; i++)
    {
        // Skip idle task for detailed reporting
        if (strcmp((const char*)pxTaskStatusArrayAfter[i].pcTaskName, "IDLE") != 0)
        {
            // Calculate CPU percentage
            if (ulRunTimeDiff > 0)
            {
                flPercentage = ((float)(pxTaskStatusArrayAfter[i].ulRunTimeCounter - 
                                       pxTaskStatusArrayBefore[i].ulRunTimeCounter)) / 
                              ((float)ulRunTimeDiff) * 100.0f;
            }
            else
            {
                flPercentage = 0.0f;
            }

            // Print task information
            printf("%-20s %-15s %-9.1f%% %-10lu\n",
                   pxTaskStatusArrayAfter[i].pcTaskName,
                   (pxTaskStatusArrayAfter[i].eCurrentState == eRunning) ? "Running" :
                   (pxTaskStatusArrayAfter[i].eCurrentState == eReady) ? "Ready" :
                   (pxTaskStatusArrayAfter[i].eCurrentState == eBlocked) ? "Blocked" : "Other",
                   flPercentage,
                   pxTaskStatusArrayAfter[i].usStackHighWaterMark);
        }
    }

    // Check for newly created tasks during measurement period
    // This requires tracking tasks across the measurement period
    // For simplicity, we'll check for tasks that might have been created/deleted

    // Print summary
    printf("-----------------------------------------\n");
    printf("Total Tasks: %lu\n", uxArraySize);
    printf("Measurement Period: %lu ticks\n", delayTicks);
    printf("Total Run Time: %lu ticks\n", ulRunTimeDiff);

    // Free allocated memory
    vPortFree(pxTaskStatusArrayBefore);
    vPortFree(pxTaskStatusArrayAfter);
}

bool AudioService::Initialize(AudioCodec* codec)
{
    // Validate input parameter
    if (codec == nullptr)
    {
        return false;
    }

    // Configure the audio codec
    if (!codec->Configure())
    {
        return false;
    }

    // Initialize Opus encoder wrapper
    if (!opus_encoder_wrapper_.Initialize())
    {
        return false;
    }

    // Initialize Opus decoder wrapper
    if (!opus_decoder_wrapper_.Initialize())
    {
        return false;
    }

    // Setup resamplers for input audio
    if (!input_resampler_.Initialize())
    {
        return false;
    }

    // Initialize audio processor for voice activity detection (VAD)
    if (!vad_processor_.Initialize())
    {
        return false;
    }

    // Setup audio power state management timer
    if (!power_state_timer_.Initialize())
    {
        return false;
    }

    // Set up callback mechanisms for communication with other system components
    if (!SetupCallbacks())
    {
        return false;
    }

    // Initialize audio buffer management
    if (!audio_buffer_manager_.Initialize())
    {
        return false;
    }

    // Configure audio processing pipeline parameters
    if (!ConfigurePipelineParameters())
    {
        return false;
    }

    // Set initial audio state
    audio_state_ = AudioState::IDLE;

    // Register with system services for audio events
    if (!RegisterWithSystemServices())
    {
        return false;
    }

    return true;
}

void AudioService::Start()
{
    // Clear all event flags to ensure clean state
    osEventFlagsClear(m_audioEventFlags);

    // Start periodic power timer for audio processing
    m_powerTimer.Start();

    // Configure task priorities and core affinity based on audio processing enablement
    if (m_audioProcessingEnabled)
    {
        // Create dedicated task for audio input processing
        m_audioInputTask = osThreadNew(
            AudioInputTaskEntry,
            this,
            &audioInputTaskAttributes
        );

        // Create dedicated task for audio output processing
        m_audioOutputTask = osThreadNew(
            AudioOutputTaskEntry,
            this,
            &audioOutputTaskAttributes
        );

        // Create dedicated task for Opus codec processing
        m_opusCodecTask = osThreadNew(
            OpusCodecTaskEntry,
            this,
            &opusCodecTaskAttributes
        );

        // Set task priorities for real-time audio handling
        osThreadSetPriority(m_audioInputTask, AUDIO_INPUT_TASK_PRIORITY);
        osThreadSetPriority(m_audioOutputTask, AUDIO_OUTPUT_TASK_PRIORITY);
        osThreadSetPriority(m_opusCodecTask, OPUS_CODEC_TASK_PRIORITY);

        // Configure core affinity for optimal resource utilization
        osThreadSetCoreAffinity(m_audioInputTask, AUDIO_INPUT_CORE_AFFINITY);
        osThreadSetCoreAffinity(m_audioOutputTask, AUDIO_OUTPUT_CORE_AFFINITY);
        osThreadSetCoreAffinity(m_opusCodecTask, OPUS_CODEC_CORE_AFFINITY);
    }
    else
    {
        // If audio processing is disabled, create minimal tasks or skip task creation
        // This ensures efficient resource utilization when audio is not needed
        m_audioInputTask = nullptr;
        m_audioOutputTask = nullptr;
        m_opusCodecTask = nullptr;
    }

    // Signal that audio service has been started successfully
    osEventFlagsSet(m_audioEventFlags, AUDIO_SERVICE_STARTED_FLAG);
}

int ReadAudioData(std::vector<int16_t>& audioBuffer, int desiredSampleRate, int channels) {
    // Initialize variables
    int actualSampleRate = 48000; // Default sample rate
    int bytesPerSample = 2; // 16-bit samples
    int totalSamples = 0;

    // Check if audio buffer is valid
    if (audioBuffer.empty()) {
        return -1; // Error: invalid buffer
    }

    // Enable audio codec if it's inactive (power saving)
    if (!isAudioCodecActive()) {
        enableAudioCodec();
        // Wait for codec to stabilize
        usleep(1000); // 1ms delay for stabilization
    }

    // Determine actual sample rate from hardware
    actualSampleRate = getActualSampleRate();

    // Calculate expected number of samples based on desired sample rate
    int expectedSamples = audioBuffer.size() / channels;

    // Capture raw audio data from microphone
    int bytesRead = captureRawAudioData(audioBuffer.data(), audioBuffer.size() * bytesPerSample);

    if (bytesRead <= 0) {
        return -2; // Error: failed to capture audio data
    }

    // Convert bytes to samples
    totalSamples = bytesRead / bytesPerSample;

    // Handle sample rate conversion if needed
    if (actualSampleRate != desiredSampleRate) {
        // Perform resampling
        std::vector<int16_t> tempBuffer(totalSamples * channels);

        // Resample audio data
        int resampledSamples = resampleAudioData(
            audioBuffer.data(), 
            totalSamples, 
            channels, 
            actualSampleRate, 
            desiredSampleRate,
            tempBuffer.data()
        );

        // Update buffer with resampled data
        if (resampledSamples > 0) {
            audioBuffer.resize(resampledSamples * channels);
            std::copy(tempBuffer.begin(), tempBuffer.begin() + resampledSamples * channels, audioBuffer.begin());
            totalSamples = resampledSamples;
        }
    }

    // Update internal statistics
    updateAudioStatistics(totalSamples, channels, desiredSampleRate);

    // Update debugging information
    updateDebugInfo("AudioCapture", totalSamples, channels, desiredSampleRate);

    // Disable audio codec if not actively needed (power saving)
    if (shouldDisableAudioCodec()) {
        disableAudioCodec();
    }

    // Return number of samples processed
    return totalSamples * channels;
}

void AudioInputTask()
{
    // Initialize audio capture buffer
    static int16_t audioBuffer[AUDIO_BUFFER_SIZE];

    // Main task loop
    while (true)
    {
        // Check if task should stop
        if (audioInputTaskStopFlag)
        {
            break;
        }

        // Capture audio frame from microphone
        int32_t framesRead = AudioCaptureFrame(audioBuffer, AUDIO_BUFFER_SIZE);

        // Validate captured data
        if (framesRead <= 0)
        {
            // Handle capture error or no data
            osDelay(1); // Small delay before next attempt
            continue;
        }

        // Get current system state
        SystemState currentState = GetCurrentSystemState();

        // Route audio data based on system state
        switch (currentState)
        {
            case SYSTEM_STATE_AUDIO_TESTING:
                // Handle audio testing mode
                AudioTestingProcess(audioBuffer, framesRead);
                break;

            case SYSTEM_STATE_WAKE_WORD_DETECTION:
                // Handle wake word detection
                WakeWordDetectionProcess(audioBuffer, framesRead);
                break;

            case SYSTEM_STATE_GENERAL_AUDIO_PROCESSING:
                // Handle general audio processing
                GeneralAudioProcessing(audioBuffer, framesRead);
                break;

            case SYSTEM_STATE_IDLE:
            default:
                // Handle idle state - may just discard or store for later
                break;
        }

        // Update audio input statistics
        audioInputFramesProcessed++;
        audioInputBytesProcessed += (framesRead * sizeof(int16_t));

        // Small delay to prevent excessive CPU usage
        // This ensures the task doesn't monopolize the CPU
        osDelay(AUDIO_TASK_DELAY_MS);
    }

    // Cleanup resources when task stops
    AudioCleanup();
}

void AudioOutputTask()
{
    // Initialize variables
    bool audioOutputEnabled = false;
    uint32_t playbackBytes = 0;
    uint32_t totalPlaybackTime = 0;
    uint32_t lastTimestamp = 0;

    // Main task loop
    while (!serviceStopped)
    {
        // Check if there's audio data in the queue
        if (audioQueueHasData())
        {
            // Process audio data from queue
            AudioPacket* packet = audioQueueDequeue();

            if (packet != NULL)
            {
                // Enable audio output if not already enabled
                if (!audioOutputEnabled)
                {
                    enableAudioOutput();
                    audioOutputEnabled = true;
                }

                // Send audio data to codec for output
                sendToAudioCodec(packet->data, packet->length);

                // Update playback statistics
                playbackBytes += packet->length;
                totalPlaybackTime += packet->duration;

                // Record timestamp for AEC if enabled
                if (aecRecordingEnabled)
                {
                    uint32_t currentTimestamp = getCurrentTimestamp();
                    recordAECTimestamp(currentTimestamp, packet->timestamp);
                    lastTimestamp = currentTimestamp;
                }

                // Free the packet memory
                freeAudioPacket(packet);
            }
        }
        else
        {
            // No data available, check if we need to disable audio output
            if (audioOutputEnabled && !audioQueueHasData())
            {
                // Optional: Add a small delay to prevent busy waiting
                delayMicroseconds(1000);
            }
        }

        // Update playback statistics periodically
        if (totalPlaybackTime > 0 && totalPlaybackTime % 1000 == 0)
        {
            updatePlaybackStats(playbackBytes, totalPlaybackTime);
        }

        // Check for service stop condition
        if (shouldStopService())
        {
            serviceStopped = true;
        }
    }

    // Cleanup and disable audio output when stopping
    if (audioOutputEnabled)
    {
        disableAudioOutput();
        audioOutputEnabled = false;
    }

    // Final cleanup of remaining audio data
    while (audioQueueHasData())
    {
        AudioPacket* packet = audioQueueDequeue();
        if (packet != NULL)
        {
            freeAudioPacket(packet);
        }
    }
}

void AudioService::OpusCodecTask()
{
    // Initialize Opus encoder and decoder
    OpusEncoder* encoder = nullptr;
    OpusDecoder* decoder = nullptr;

    // Initialize sample rates and buffer sizes
    int sample_rate = 48000;  // Default sample rate
    int channels = 2;         // Stereo audio
    int frame_size = 960;     // 20ms at 48kHz

    // Create encoder
    int error;
    encoder = opus_encoder_create(sample_rate, channels, OPUS_APPLICATION_AUDIO, &error);
    if (error != OPUS_OK || encoder == nullptr) {
        // Handle encoder creation failure
        return;
    }

    // Create decoder
    decoder = opus_decoder_create(sample_rate, channels, &error);
    if (error != OPUS_OK || decoder == nullptr) {
        // Handle decoder creation failure
        opus_encoder_destroy(encoder);
        return;
    }

    // Set encoder parameters for optimal performance
    opus_encoder_ctl(encoder, OPUS_SET_BITRATE(64000));  // 64 kbps bitrate
    opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(10));   // Maximum complexity
    opus_encoder_ctl(encoder, OPUS_SET_PACKET_LOSS_PERC(1)); // Assume 1% loss

    // Initialize queues with appropriate sizes
    const size_t MAX_INPUT_QUEUE_SIZE = 100;
    const size_t MAX_OUTPUT_QUEUE_SIZE = 100;

    // Process incoming audio data
    while (true) {
        // Check for new PCM data in input queue
        if (!input_pcm_queue.empty()) {
            // Get PCM data from queue with timeout
            std::vector<int16_t> pcm_data;
            if (input_pcm_queue.pop(pcm_data, 10)) {  // 10ms timeout
                // Validate PCM data
                if (pcm_data.size() >= frame_size * channels) {
                    // Encode PCM to Opus
                    std::vector<uint8_t> opus_packet(OPUS_MAX_PACKET_SIZE);
                    int packet_length = opus_encode(encoder, 
                                                   pcm_data.data(), 
                                                   frame_size, 
                                                   opus_packet.data(), 
                                                   opus_packet.size());

                    if (packet_length > 0) {
                        // Add encoded packet to output queue
                        if (output_opus_queue.size() < MAX_OUTPUT_QUEUE_SIZE) {
                            output_opus_queue.push(opus_packet);

                            // Signal that new data is available for transmission
                            data_available_signal.notify_one();
                        } else {
                            // Handle queue overflow - drop oldest packet
                            output_opus_queue.pop();
                            output_opus_queue.push(opus_packet);
                        }
                    }
                }
            }
        }

        // Check for incoming Opus packets
        if (!input_opus_queue.empty()) {
            // Get Opus packet from queue
            std::vector<uint8_t> opus_packet;
            if (input_opus_queue.pop(opus_packet, 10)) {
                // Decode Opus to PCM
                std::vector<int16_t> pcm_output(frame_size * channels);
                int decoded_samples = opus_decode(decoder, 
                                                 opus_packet.data(), 
                                                 opus_packet.size(), 
                                                 pcm_output.data(), 
                                                 frame_size, 
                                                 0);

                if (decoded_samples > 0) {
                    // Add decoded PCM to output queue
                    if (output_pcm_queue.size() < MAX_OUTPUT_QUEUE_SIZE) {
                        output_pcm_queue.push(pcm_output);

                        // Signal that decoded audio is available for playback
                        playback_ready_signal.notify_one();
                    } else {
                        // Handle queue overflow - drop oldest packet
                        output_pcm_queue.pop();
                        output_pcm_queue.push(pcm_output);
                    }
                }
            }
        }

        // Maintain queue limits to prevent overflow
        while (input_pcm_queue.size() > MAX_INPUT_QUEUE_SIZE) {
            std::vector<int16_t> temp;
            input_pcm_queue.pop(temp);
        }

        while (input_opus_queue.size() > MAX_INPUT_QUEUE_SIZE) {
            std::vector<uint8_t> temp;
            input_opus_queue.pop(temp);
        }

        // Periodic maintenance tasks
        static uint32_t last_maintenance = 0;
        uint32_t current_time = millis();

        if (current_time - last_maintenance > 1000) {  // Every second
            // Update encoder/decoder parameters if needed
            opus_encoder_ctl(encoder, OPUS_SET_BITRATE(64000));

            // Reset maintenance timer
            last_maintenance = current_time;
        }

        // Small delay to prevent excessive CPU usage
        delayMicroseconds(1000);  // 1ms delay
    }

    // Cleanup resources
    opus_encoder_destroy(encoder);
    opus_decoder_destroy(decoder);
}

bool PushTaskToEncodeQueue(AudioTaskType task_type, std::vector<int16_t>&& audio_data) {
    // Check if the task type is valid
    if (task_type != kAudioTaskTypeEncodeToSendQueue && task_type != kAudioTaskTypeEncodeForRecording) {
        return false;
    }

    // Create the audio task with the provided data
    AudioTask task;
    task.type = task_type;
    task.audio_data = std::move(audio_data);

    // For tasks of type kAudioTaskTypeEncodeToSendQueue, we need to associate a timestamp
    if (task_type == kAudioTaskTypeEncodeToSendQueue) {
        // Acquire mutex for thread-safe access to timestamp queue
        std::lock_guard<std::mutex> lock(timestamp_mutex_);

        // Check if there are available timestamps
        if (!timestamp_queue_.empty()) {
            task.timestamp = timestamp_queue_.front();
            timestamp_queue_.pop();
        } else {
            // If no timestamp available, use current time as fallback
            task.timestamp = std::chrono::duration_cast<std::chrono::milliseconds>(
                std::chrono::system_clock::now().time_since_epoch()).count();
        }
    }

    // Acquire mutex for thread-safe access to encode queue
    std::lock_guard<std::mutex> lock(queue_mutex_);

    // Wait if queue is full (using condition variable)
    while (encode_queue_.size() >= MAX_QUEUE_SIZE) {
        // Wait for space in queue
        queue_not_full_cv_.wait(lock);
    }

    // Add task to the queue
    encode_queue_.push(task);

    // Notify waiting consumers that new data is available
    queue_not_empty_cv_.notify_one();

    return true;
}

void EnableWakeWordDetection(bool enable)
{
    static bool isInitialized = false;
    static bool isDetectionActive = false;

    if (enable)
    {
        // Enable wake word detection
        if (!isInitialized)
        {
            // Initialize the wake word detection system
            // This would typically involve setting up hardware, loading models, etc.
            InitializeWakeWordDetection();
            isInitialized = true;
        }

        // Start the detection process
        if (!isDetectionActive)
        {
            StartWakeWordDetection();
            isDetectionActive = true;
        }

        // Set the event flag to indicate wake word detection is enabled
        SetWakeWordDetectionEventFlag(true);
    }
    else
    {
        // Disable wake word detection
        if (isDetectionActive)
        {
            // Stop the detection process
            StopWakeWordDetection();
            isDetectionActive = false;
        }

        // Clear the event flag to indicate wake word detection is disabled
        SetWakeWordDetectionEventFlag(false);
    }
}

void AudioService::PlaySound(const std::string_view& filename) {
    // Enable audio output if it's disabled
    if (!isAudioOutputEnabled()) {
        enableAudioOutput();
    }

    // Open the OGG file for reading
    std::ifstream file(filename.data(), std::ios::binary);
    if (!file.is_open()) {
        // Handle error - could not open file
        return;
    }

    // Read and parse OGG container structure
    // First, read the OGG page header to identify the stream
    char ogg_header[27];
    file.read(ogg_header, 27);

    // Verify this is a valid OGG file by checking the magic number
    if (memcmp(ogg_header, "OggS", 4) != 0) {
        // Invalid OGG file
        return;
    }

    // Parse OGG page header
    uint32_t page_header[6];
    memcpy(page_header, ogg_header, 27);

    // Extract page sequence number and other metadata
    uint32_t page_sequence = page_header[5];

    // Look for the beginning of the audio stream
    bool found_audio_stream = false;
    while (!found_audio_stream && file.good()) {
        // Read page header
        char page_header_data[27];
        if (file.read(page_header_data, 27).gcount() != 27) {
            break; // End of file or error
        }

        // Check if this is a valid OGG page
        if (memcmp(page_header_data, "OggS", 4) != 0) {
            continue; // Not a valid page, skip to next
        }

        // Get page segment count
        uint8_t segment_count = static_cast<uint8_t>(page_header_data[26]);

        // Read all segments
        std::vector<uint8_t> segments(segment_count);
        if (file.read(reinterpret_cast<char*>(segments.data()), segment_count).gcount() != segment_count) {
            break;
        }

        // Calculate total page size
        uint32_t page_size = 0;
        for (uint8_t segment : segments) {
            page_size += segment;
        }

        // Skip the page data (we're looking for audio headers)
        file.seekg(page_size, std::ios::cur);

        // Check if this page contains the beginning of the audio stream
        // For simplicity, we'll assume the first audio page we find is what we want
        found_audio_stream = true;
    }

    // Reset file position to beginning for actual parsing
    file.clear();
    file.seekg(0, std::ios::beg);

    // Parse the complete OGG file to find the Opus header
    bool opus_header_found = false;
    uint32_t sample_rate = 48000; // Default sample rate
    uint16_t channels = 2;         // Default stereo

    // Read through OGG pages to find Opus header
    while (file.good() && !opus_header_found) {
        // Read page header
        char page_header[27];
        if (file.read(page_header, 27).gcount() != 27) {
            break;
        }

        // Validate OGG page
        if (memcmp(page_header, "OggS", 4) != 0) {
            continue;
        }

        // Get segment count
        uint8_t segment_count = static_cast<uint8_t>(page_header[26]);

        // Read segments
        std::vector<uint8_t> segments(segment_count);
        if (file.read(reinterpret_cast<char*>(segments.data()), segment_count).gcount() != segment_count) {
            break;
        }

        // Calculate page size
        uint32_t page_size = 0;
        for (uint8_t segment : segments) {
            page_size += segment;
        }

        // Read page data
        std::vector<uint8_t> page_data(page_size);
        if (file.read(reinterpret_cast<char*>(page_data.data()), page_size).gcount() != page_size) {
            break;
        }

        // Check if this page contains the Opus identification header
        // The Opus header starts with "OpusHead" magic bytes
        if (page_data.size() >= 8 && memcmp(page_data.data(), "OpusHead", 8) == 0) {
            // Parse Opus header to get sample rate and channel info
            // Opus header format:
            // [0-7]   : "OpusHead"
            // [8]     : Version (should be 1)
            // [9]     : Output Channel Count
            // [10-11] : Pre-skip (in samples)
            // [12-15] : Input Sample Rate (in Hz)
            // [16-17] : Output Gain (in dB)
            // [18]    : Channel Mapping Family

            if (page_data.size() >= 20) {
                channels = page_data[9];
                sample_rate = (static_cast<uint32_t>(page_data[12]) << 0) |
                             (static_cast<uint32_t>(page_data[13]) << 8) |
                             (static_cast<uint32_t>(page_data[14]) << 16) |
                             (static_cast<uint32_t>(page_data[15]) << 24);

                opus_header_found = true;
            }
        }

        // If we've found the header, we can now start processing audio packets
        if (opus_header_found) {
            // Configure audio output with parsed parameters
            configureAudioOutput(sample_rate, channels);

            // Process remaining audio packets
            while (file.good()) {
                // Read next page header
                char next_page_header[27];
                if (file.read(next_page_header, 27).gcount() != 27) {
                    break;
                }

                if (memcmp(next_page_header, "OggS", 4) != 0) {
                    continue;
                }

                // Get segment count
                uint8_t segment_count = static_cast<uint8_t>(next_page_header[26]);

                // Read segments
                std::vector<uint8_t> segments(segment_count);
                if (file.read(reinterpret_cast<char*>(segments.data()), segment_count).gcount() != segment_count) {
                    break;
                }

                // Calculate page size
                uint32_t page_size = 0;
                for (uint8_t segment : segments) {
                    page_size += segment;
                }

                // Read page data
                std::vector<uint8_t> page_data(page_size);
                if (file.read(reinterpret_cast<char*>(page_data.data()), page_size).gcount() != page_size) {
                    break;
                }

                // Check if this page contains Opus audio data (not headers)
                if (page_data.size() >= 8 && memcmp(page_data.data(), "OpusTags", 8) != 0) {
                    // Send decoded audio data to output device
                    // In a real implementation, this would involve decoding Opus packets
                    // and sending them to the audio hardware

                    // For demonstration, we'll just simulate sending audio data
                    sendAudioDataToOutput(page_data.data(), page_data.size());
                }
            }
            break;
        }
    }

    // Close the file
    file.close();
}

void AudioService::SetModelsList(srmodel_list_t *models)
{
    // Store the models list
    m_models = models;

    // Clear existing wake word engine
    if (m_wakeWordEngine != nullptr)
    {
        delete m_wakeWordEngine;
        m_wakeWordEngine = nullptr;
    }

    // Initialize wake word engine based on model prefixes and platform configuration
    bool engineInitialized = false;

    // Check if we have any models
    if (models == nullptr || models->count == 0)
    {
        return;
    }

    // Check for custom wake word models (starting with "custom:")
    bool hasCustomModels = false;
    bool hasAFEModels = false;
    bool hasESPModels = false;

    for (int i = 0; i < models->count; i++)
    {
        if (models->models[i].name != nullptr)
        {
            std::string modelName(models->models[i].name);

            if (modelName.find("custom:") == 0)
            {
                hasCustomModels = true;
            }
            else if (modelName.find("afe:") == 0)
            {
                hasAFEModels = true;
            }
            else if (modelName.find("esp:") == 0)
            {
                hasESPModels = true;
            }
        }
    }

    // Select appropriate wake word engine based on platform and model types
    #ifdef PLATFORM_AFE
        // Use AFE-based wake word engine if available
        if (hasAFEModels)
        {
            m_wakeWordEngine = new AFEWakeWordEngine();
            engineInitialized = true;
        }
        else if (hasCustomModels)
        {
            m_wakeWordEngine = new CustomWakeWordEngine();
            engineInitialized = true;
        }
    #elif defined(PLATFORM_ESP)
        // Use ESP-based wake word engine
        if (hasESPModels)
        {
            m_wakeWordEngine = new ESPWakeWordEngine();
            engineInitialized = true;
        }
        else if (hasCustomModels)
        {
            m_wakeWordEngine = new CustomWakeWordEngine();
            engineInitialized = true;
        }
    #else
        // Default to custom wake word engine
        if (hasCustomModels)
        {
            m_wakeWordEngine = new CustomWakeWordEngine();
            engineInitialized = true;
        }
        else if (hasAFEModels)
        {
            m_wakeWordEngine = new AFEWakeWordEngine();
            engineInitialized = true;
        }
        else if (hasESPModels)
        {
            m_wakeWordEngine = new ESPWakeWordEngine();
            engineInitialized = true;
        }
    #endif

    // Initialize the selected engine if one was chosen
    if (engineInitialized && m_wakeWordEngine != nullptr)
    {
        // Initialize the wake word engine with the provided models
        if (m_wakeWordEngine->Initialize(models) == true)
        {
            // Register callback for wake word detection events
            m_wakeWordEngine->SetDetectionCallback([this](const char* wakeWord, int confidence)
            {
                // Handle wake word detection event
                OnWakeWordDetected(wakeWord, confidence);
            });
        }
        else
        {
            // If initialization fails, clean up
            delete m_wakeWordEngine;
            m_wakeWordEngine = nullptr;
        }
    }

    // Update system state based on available models
    m_hasWakeWordModels = (m_wakeWordEngine != nullptr);
    m_hasSpeechRecognitionModels = (models->count > 0);
}

esp_err_t CreateDuplexChannels(gpio_num_t bck_pin, gpio_num_t ws_pin, gpio_num_t sd_pin, gpio_num_t mclk_pin, gpio_num_t din_pin)
{
    // Configure I2S parameters for full-duplex operation
    i2s_config_t i2s_config = {
        .mode = (i2s_mode_t)(I2S_MODE_MASTER | I2S_MODE_TX | I2S_MODE_RX),
        .sample_rate = 44100,  // Standard audio sample rate
        .bits_per_sample = I2S_BITS_PER_SAMPLE_16BIT,
        .channel_format = I2S_CHANNEL_FMT_RIGHT_LEFT,
        .communication_format = I2S_COMM_FORMAT_I2S,
        .dma_buf_count = 8,
        .dma_buf_len = 64,
        .use_apll = false,
        .tx_desc_auto_clear = true,
        .fixed_mclk = 0
    };

    // Configure I2S pin configuration
    i2s_pin_config_t pin_config = {
        .bck_io_num = bck_pin,
        .ws_io_num = ws_pin,
        .data_out_num = sd_pin,
        .data_in_num = din_pin
    };

    // Install and start I2S driver
    esp_err_t ret = i2s_driver_install(I2S_NUM_0, &i2s_config, 0, NULL);
    if (ret != ESP_OK) {
        return ret;
    }

    // Set up I2S pins
    ret = i2s_set_pin(I2S_NUM_0, &pin_config);
    if (ret != ESP_OK) {
        i2s_driver_uninstall(I2S_NUM_0);
        return ret;
    }

    // Configure MCLK if provided
    if (mclk_pin != GPIO_NUM_NC) {
        gpio_set_direction(mclk_pin, GPIO_MODE_OUTPUT);
        gpio_set_level(mclk_pin, 1);
    }

    // Set I2S sample rate (redundant but ensures proper configuration)
    ret = i2s_set_sample_rates(I2S_NUM_0, 44100);
    if (ret != ESP_OK) {
        i2s_driver_uninstall(I2S_NUM_0);
        return ret;
    }

    // Configure I2S for full-duplex operation
    // Enable both transmit and receive channels
    i2s_enable_tx(I2S_NUM_0);
    i2s_enable_rx(I2S_NUM_0);

    return ESP_OK;
}

void EnableInput(bool enable)
{
    if (enable)
    {
        // Enable audio input functionality
        // Configure input device settings
        ConfigureAudioInputDevice(48000, 16, 2); // Sample rate: 48kHz, Bit depth: 16-bit, Channels: 2

        // Apply fixed gain or adjustable input gain
        // Using fixed gain as default - can be modified based on requirements
        SetInputGain(30); // Set gain to 30dB (example value)

        // Open the input device to start audio capture
        OpenAudioInputDevice();

        // Additional ES8388 specific configuration
        ES8388_SetInputMode(INPUT_MODE_MIC); // Set to microphone input mode
        ES8388_EnableInput(true); // Enable the input path in codec
    }
    else
    {
        // Disable audio input functionality
        // Close the input device to stop audio capture
        CloseAudioInputDevice();

        // Disable the input path in ES8388 codec
        ES8388_EnableInput(false);

        // Reset gain settings
        SetInputGain(0); // Reset gain to 0dB
    }
}

void EnableOutput(bool enable)
{
    if (enable)
    {
        // Enable audio output - configure codec settings

        // Configure sample rate (assuming 48kHz as default)
        // This would typically involve writing to codec register for sample rate
        WriteCodecRegister(ES8388_SAMPLE_RATE_REG, SAMPLE_RATE_48KHZ);

        // Set volume level (example: 0dB)
        // This would typically involve writing to volume control registers
        WriteCodecRegister(ES8388_VOLUME_REG, VOLUME_0DB);

        // Configure analog output levels
        // Set headphone amplification
        WriteCodecRegister(ES8388_ANALOG_CTRL1_REG, ANALOG_CTRL1_HEADPHONE_ENABLE);

        // Set speaker amplification
        WriteCodecRegister(ES8388_ANALOG_CTRL2_REG, ANALOG_CTRL2_SPEAKER_ENABLE);

        // Enable power amplifier if present
        if (POWER_AMPLIFIER_PIN != GPIO_NONE)
        {
            GPIO_SetPin(POWER_AMPLIFIER_PIN, GPIO_HIGH);
        }

        // Enable codec output path
        WriteCodecRegister(ES8388_DAC_CTRL_REG, DAC_CTRL_OUTPUT_ENABLE);

        // Wait for stabilization
        DelayMs(10);
    }
    else
    {
        // Disable audio output - clean up codec settings

        // Disable codec output path
        WriteCodecRegister(ES8388_DAC_CTRL_REG, DAC_CTRL_OUTPUT_DISABLE);

        // Disable analog output levels
        WriteCodecRegister(ES8388_ANALOG_CTRL1_REG, ANALOG_CTRL1_HEADPHONE_DISABLE);
        WriteCodecRegister(ES8388_ANALOG_CTRL2_REG, ANALOG_CTRL2_SPEAKER_DISABLE);

        // Set volume to minimum/zero
        WriteCodecRegister(ES8388_VOLUME_REG, VOLUME_MIN);

        // Disable power amplifier if present
        if (POWER_AMPLIFIER_PIN != GPIO_NONE)
        {
            GPIO_SetPin(POWER_AMPLIFIER_PIN, GPIO_LOW);
        }

        // Close codec output device
        CloseCodecOutput();

        // Wait for stabilization
        DelayMs(10);
    }
}

AudioDebugger::AudioDebugger(const std::string& serverIp, int serverPort)
{
    // Initialize logging
    Logger::log("AudioDebugger: Initializing UDP socket connection");

    // Store server configuration
    m_serverIp = serverIp;
    m_serverPort = serverPort;

    // Initialize socket
    m_socketFd = socket(AF_INET, SOCK_DGRAM, 0);
    if (m_socketFd < 0) {
        Logger::log("AudioDebugger: Failed to create UDP socket", LogLevel::ERROR);
        m_initialized = false;
        return;
    }

    // Set up server address structure
    memset(&m_serverAddr, 0, sizeof(m_serverAddr));
    m_serverAddr.sin_family = AF_INET;
    m_serverAddr.sin_port = htons(serverPort);

    // Parse IP address
    if (inet_pton(AF_INET, serverIp.c_str(), &m_serverAddr.sin_addr) <= 0) {
        Logger::log("AudioDebugger: Failed to parse server IP address", LogLevel::ERROR);
        close(m_socketFd);
        m_initialized = false;
        return;
    }

    // Set socket options for better performance
    int opt = 1;
    if (setsockopt(m_socketFd, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt)) < 0) {
        Logger::log("AudioDebugger: Failed to set socket options", LogLevel::WARNING);
    }

    // Log successful initialization
    Logger::log("AudioDebugger: UDP socket initialized successfully");
    Logger::log("AudioDebugger: Connected to " + serverIp + ":" + std::to_string(serverPort));

    m_initialized = true;
}

bool AfeWakeWord::Initialize(AudioCodec *codec, srmodel_list_t *model_list)
{
    // Validate input parameters
    if (!codec || !model_list) {
        return false;
    }

    // Configure the audio codec
    if (!codec->Configure()) {
        return false;
    }

    // Load wake word models
    for (int i = 0; i < model_list->num_models; i++) {
        if (!LoadModel(model_list->models[i])) {
            return false;
        }
    }

    // Initialize AFE processing pipeline
    if (!InitializePipeline()) {
        return false;
    }

    // Configure echo cancellation
    if (!ConfigureEchoCancellation()) {
        return false;
    }

    // Allocate memory for processing
    if (!AllocateMemory()) {
        return false;
    }

    // Start dedicated task for audio detection
    if (!StartDetectionTask()) {
        return false;
    }

    // Mark initialization as successful
    m_initialized = true;
    return true;
}

void AfeWakeWord::AudioDetectionTask()
{
    // Initialize variables
    bool detectionActive = true;
    bool wakeWordDetected = false;
    std::string detectedWakeWord;

    // Main detection loop
    while (detectionActive)
    {
        // Check if audio data is available from the acoustic front-end
        if (acousticFrontEnd->isAudioAvailable())
        {
            // Read audio data
            AudioData audioBuffer = acousticFrontEnd->readAudioData();

            // Process audio data for wake word detection
            WakeWordResult result = wakeWordDetector->detectWakeWord(audioBuffer);

            // Check if wake word was detected
            if (result.isDetected)
            {
                // Stop the detection process
                detectionActive = false;
                wakeWordDetected = true;
                detectedWakeWord = result.wakeWord;

                // Store the relevant audio data
                storedAudioData = audioBuffer;

                // Trigger callback with the identified wake word
                if (wakeWordCallback != nullptr)
                {
                    wakeWordCallback(detectedWakeWord);
                }

                // Break out of the loop as detection is complete
                break;
            }
        }

        // Add small delay to prevent excessive CPU usage
        Thread::sleep(10); // 10ms delay

        // Check for external stop signal (if implemented)
        if (shouldStopDetection())
        {
            detectionActive = false;
        }
    }

    // Clean up resources if needed
    if (!wakeWordDetected)
    {
        // Handle case where no wake word was detected within timeout
        // Could trigger timeout callback or logging
    }
}

void AfeWakeWord::EncodeWakeWordData()
{
    // Initialize Opus encoder with low complexity settings for fast encoding
    OpusEncoder* encoder = opus_encoder_create(16000, 1, OPUS_APPLICATION_VOIP, NULL);
    if (encoder == NULL) {
        // Handle encoder creation failure
        return;
    }

    // Set encoder parameters for low complexity and fast encoding
    opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(0));
    opus_encoder_ctl(encoder, OPUS_SET_BITRATE(24000));
    opus_encoder_ctl(encoder, OPUS_SET_VBR(0));

    // Allocate memory for Opus packet buffer
    uint8_t* opus_packet_buffer = (uint8_t*)heap_caps_malloc(OPUS_MAX_PACKET_SIZE, MALLOC_CAP_SPIRAM);
    if (opus_packet_buffer == NULL) {
        // Handle memory allocation failure
        opus_encoder_destroy(encoder);
        return;
    }

    // Main encoding loop
    while (true) {
        // Wait for new PCM data to be available
        std::unique_lock<std::mutex> lock(pcm_mutex_);
        pcm_condition_.wait(lock, [this] { return !pcm_queue_.empty(); });

        // Get the next PCM packet
        std::vector<int16_t> pcm_packet = pcm_queue_.front();
        pcm_queue_.pop();

        // Unlock mutex before processing to avoid blocking other operations
        lock.unlock();

        // Encode PCM data to Opus format
        int opus_packet_size = opus_encode(encoder, 
                                          pcm_packet.data(), 
                                          pcm_packet.size() / sizeof(int16_t),
                                          opus_packet_buffer, 
                                          OPUS_MAX_PACKET_SIZE);

        if (opus_packet_size > 0) {
            // Create Opus packet structure
            OpusPacket opus_packet;
            opus_packet.size = opus_packet_size;
            opus_packet.data = (uint8_t*)heap_caps_malloc(opus_packet_size, MALLOC_CAP_SPIRAM);

            if (opus_packet.data != NULL) {
                memcpy(opus_packet.data, opus_packet_buffer, opus_packet_size);

                // Add encoded packet to thread-safe buffer
                std::lock_guard<std::mutex> buffer_lock(buffer_mutex_);
                opus_buffer_.push(opus_packet);

                // Signal completion via condition variable
                buffer_condition_.notify_one();
            } else {
                // Handle memory allocation failure for packet data
                ESP_LOGE(TAG, "Failed to allocate memory for Opus packet data");
            }
        } else {
            // Handle encoding error
            ESP_LOGE(TAG, "Opus encoding failed with error: %d", opus_packet_size);
        }

        // Check if we should exit the loop (shutdown signal)
        if (shutdown_flag_) {
            break;
        }
    }

    // Cleanup resources
    heap_caps_free(opus_packet_buffer);
    opus_encoder_destroy(encoder);
}

bool CustomWakeWord::ParseWakenetModelConfig(const std::string& configFilePath) {
    // Open and read the JSON configuration file
    std::ifstream configFile(configFilePath);
    if (!configFile.is_open()) {
        LOG_ERROR("Failed to open configuration file: %s", configFilePath.c_str());
        return false;
    }

    // Read the entire file content into a string
    std::stringstream buffer;
    buffer << configFile.rdbuf();
    std::string jsonContent = buffer.str();
    configFile.close();

    // Parse the JSON content
    try {
        nlohmann::json configJson = nlohmann::json::parse(jsonContent);

        // Extract language setting
        if (configJson.contains("language")) {
            m_language = configJson["language"].get<std::string>();
            LOG_DEBUG("Parsed language: %s", m_language.c_str());
        } else {
            LOG_WARNING("Language not specified in config file");
        }

        // Extract duration setting
        if (configJson.contains("duration")) {
            m_duration = configJson["duration"].get<int>();
            LOG_DEBUG("Parsed duration: %d", m_duration);
        } else {
            LOG_WARNING("Duration not specified in config file");
        }

        // Extract threshold setting
        if (configJson.contains("threshold")) {
            m_threshold = configJson["threshold"].get<float>();
            LOG_DEBUG("Parsed threshold: %.2f", m_threshold);
        } else {
            LOG_WARNING("Threshold not specified in config file");
        }

        // Extract command definitions
        if (configJson.contains("commands") && configJson["commands"].is_array()) {
            m_commands.clear(); // Clear existing commands

            for (const auto& cmd : configJson["commands"]) {
                CommandDefinition command;

                // Parse command name
                if (cmd.contains("name")) {
                    command.name = cmd["name"].get<std::string>();
                } else {
                    LOG_WARNING("Command without name found");
                    continue;
                }

                // Parse command trigger words
                if (cmd.contains("trigger_words") && cmd["trigger_words"].is_array()) {
                    for (const auto& word : cmd["trigger_words"]) {
                        command.triggerWords.push_back(word.get<std::string>());
                    }
                }

                // Parse command parameters
                if (cmd.contains("parameters") && cmd["parameters"].is_object()) {
                    for (const auto& param : cmd["parameters"].items()) {
                        command.parameters[param.key()] = param.value().get<std::string>();
                    }
                }

                // Parse command action
                if (cmd.contains("action")) {
                    command.action = cmd["action"].get<std::string>();
                }

                // Log the parsed command for debugging
                LOG_DEBUG("Parsed command: %s", command.name.c_str());
                LOG_DEBUG("  Trigger words: %zu items", command.triggerWords.size());
                LOG_DEBUG("  Action: %s", command.action.c_str());
                LOG_DEBUG("  Parameters: %zu items", command.parameters.size());

                m_commands.push_back(command);
            }
        } else {
            LOG_WARNING("No commands found or invalid commands format in config file");
        }

        // Extract additional model parameters if present
        if (configJson.contains("model_params") && configJson["model_params"].is_object()) {
            for (const auto& param : configJson["model_params"].items()) {
                m_modelParams[param.key()] = param.value().get<std::string>();
            }
        }

        LOG_INFO("Successfully parsed wakenet model configuration from %s", configFilePath.c_str());
        return true;

    } catch (const nlohmann::json::parse_error& e) {
        LOG_ERROR("JSON parsing error in config file %s: %s", configFilePath.c_str(), e.what());
        return false;
    } catch (const std::exception& e) {
        LOG_ERROR("Error parsing configuration file %s: %s", configFilePath.c_str(), e.what());
        return false;
    }
}

