int EncodeWakeWordData()
{
    // Allocate memory for the task stack
    uint8_t* task_stack = (uint8_t*)malloc(TASK_STACK_SIZE);
    if (task_stack == NULL) {
        return -1; // Memory allocation failed
    }

    // Allocate memory for the encoded buffer
    uint8_t* encoded_buffer = (uint8_t*)malloc(ENCODED_BUFFER_SIZE);
    if (encoded_buffer == NULL) {
        free(task_stack);
        return -2; // Memory allocation failed
    }

    // Create a new task for background encoding
    TaskHandle_t encode_task = xTaskCreateStatic(
        EncodeWakeWordDataTask,
        "WakeWordEncoder",
        TASK_STACK_SIZE,
        NULL,
        TASK_PRIORITY,
        task_stack,
        NULL
    );

    if (encode_task == NULL) {
        free(task_stack);
        free(encoded_buffer);
        return -3; // Task creation failed
    }

    // Initialize Opus encoder with low complexity settings
    OpusEncoder* encoder = opus_encoder_create(SAMPLE_RATE, CHANNELS, OPUS_APPLICATION_VOIP, NULL);
    if (encoder == NULL) {
        free(task_stack);
        free(encoded_buffer);
        return -4; // Encoder creation failed
    }

    opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(0)); // Low complexity
    opus_encoder_ctl(encoder, OPUS_SET_BITRATE(BITRATE));

    // Process each PCM segment
    int total_encoded_bytes = 0;
    int segment_count = get_pcm_segment_count();

    for (int i = 0; i < segment_count; i++) {
        // Get PCM segment data
        uint8_t* pcm_data = get_pcm_segment(i);
        int pcm_length = get_pcm_segment_length(i);

        // Encode PCM data to Opus
        int encoded_bytes = opus_encode(encoder, 
                                       (opus_int16*)pcm_data, 
                                       pcm_length / sizeof(opus_int16), 
                                       encoded_buffer + total_encoded_bytes, 
                                       ENCODED_BUFFER_SIZE - total_encoded_bytes);

        if (encoded_bytes < 0) {
            // Handle encoding error
            opus_encoder_destroy(encoder);
            free(task_stack);
            free(encoded_buffer);
            return -5; // Encoding error
        }

        total_encoded_bytes += encoded_bytes;
    }

    // Append termination marker
    uint32_t termination_marker = TERMINATION_MARKER;
    memcpy(encoded_buffer + total_encoded_bytes, &termination_marker, sizeof(uint32_t));
    total_encoded_bytes += sizeof(uint32_t);

    // Signal availability of encoded data
    signal_encoded_data_ready(encoded_buffer, total_encoded_bytes);

    // Clean up resources
    opus_encoder_destroy(encoder);
    free(task_stack);
    free(encoded_buffer);

    return 0; // Success
}

