// Display configuration constants
#define ST7789_RST_PIN      0
#define ST7789_DC_PIN       1
#define ST7789_CS_PIN       2
#define ST7789_BL_PIN       3

// ST7789 command definitions
#define ST7789_CMD_SWRESET  0x01
#define ST7789_CMD_SLPOUT   0x11
#define ST7789_CMD_CSCON    0x20
#define ST7789_CMD_MADCTL   0x36
#define ST7789_CMD_COLMOD   0x3A
#define ST7789_CMD_DISPON   0x29

// Display dimensions
#define DISPLAY_WIDTH       240
#define DISPLAY_HEIGHT      320

// Global display object
static DisplayObject g_display;

void InitializeSt7789Display(DisplayObject* display)
{
    // Initialize GPIO pins for display control
    GpioInit();

    // Reset the display
    GpioSetPin(ST7789_RST_PIN, 0);
    for (volatile int i = 0; i < 100000; i++);
    GpioSetPin(ST7789_RST_PIN, 1);
    for (volatile int i = 0; i < 100000; i++);

    // Initialize SPI interface
    SpiInit();

    // Send software reset command
    SpiWriteByte(0x00); // DC pin low for command
    SpiWriteByte(ST7789_CMD_SWRESET);
    for (volatile int i = 0; i < 1000000; i++);

    // Exit sleep mode
    SpiWriteByte(0x00); // DC pin low for command
    SpiWriteByte(ST7789_CMD_SLPOUT);
    for (volatile int i = 0; i < 1000000; i++);

    // Set color mode to 65K colors (16-bit)
    SpiWriteByte(0x00); // DC pin low for command
    SpiWriteByte(ST7789_CMD_COLMOD);
    SpiWriteByte(0x05); // 16-bit color mode

    // Set memory access control - configure display orientation
    SpiWriteByte(0x00); // DC pin low for command
    SpiWriteByte(ST7789_CMD_MADCTL);
    SpiWriteByte(0x00); // Default orientation (no rotation, no mirror)

    // Enable display
    SpiWriteByte(0x00); // DC pin low for command
    SpiWriteByte(ST7789_CMD_DISPON);
    for (volatile int i = 0; i < 100000; i++);

    // Configure display object
    display->width = DISPLAY_WIDTH;
    display->height = DISPLAY_HEIGHT;
    display->color_depth = 16;
    display->buffer = NULL; // Buffer will be allocated by application

    // Apply additional display settings
    // Color inversion off
    SpiWriteByte(0x00); // DC pin low for command
    SpiWriteByte(0x20); // Color inversion command
    SpiWriteByte(0x00); // Off

    // Axis swapping and mirroring settings
    SpiWriteByte(0x00); // DC pin low for command
    SpiWriteByte(ST7789_CMD_MADCTL);
    SpiWriteByte(0x00); // Default: no swapping, no mirroring

    // Turn on backlight if needed
    GpioSetPin(ST7789_BL_PIN, 1);
}

bool InitializeCamera()
{
    // Initialize I/O expander for camera power and reset control
    if (!IoExpander_Init())
    {
        return false;
    }

    // Power up sequence - enable camera power supply
    IoExpander_SetPinState(CAMERA_POWER_PIN, PIN_HIGH);

    // Wait for power to stabilize (minimum 10ms)
    Delay_ms(10);

    // Configure DVP parallel data interface pins
    DVP_ConfigurePins();

    // Configure SCCB/I2C interface for camera communication
    SCCB_Init();

    // Reset sequence - assert reset signal
    IoExpander_SetPinState(CAMERA_RESET_PIN, PIN_LOW);

    // Wait for reset assertion time (minimum 2ms)
    Delay_ms(2);

    // Deassert reset signal
    IoExpander_SetPinState(CAMERA_RESET_PIN, PIN_HIGH);

    // Wait for camera to come out of reset (minimum 5ms)
    Delay_ms(5);

    // Verify camera is responding by reading camera ID register
    uint8_t cameraId = SCCB_ReadRegister(CAMERA_ID_REG);
    if (cameraId == 0x00 || cameraId == 0xFF)
    {
        // Camera not responding or invalid ID
        return false;
    }

    // Configure camera driver with detected parameters
    if (!CameraDriver_Init(cameraId))
    {
        return false;
    }

    // Set default camera configuration
    CameraDriver_SetResolution(CAMERA_DEFAULT_WIDTH, CAMERA_DEFAULT_HEIGHT);
    CameraDriver_SetFrameRate(CAMERA_DEFAULT_FPS);

    // Enable camera capture
    CameraDriver_EnableCapture();

    return true;
}

