class PwmBacklight {
private:
    gpio_num_t backlight_gpio;
    bool invert_output;
    uint32_t pwm_frequency;
    ledc_timer_t ledc_timer;
    ledc_channel_t ledc_channel;

public:
    PwmBacklight(gpio_num_t gpio_num, bool invert, uint32_t freq) 
        : backlight_gpio(gpio_num), invert_output(invert), pwm_frequency(freq) {

        // Initialize the LEDC timer
        ledc_timer_config_t timer_conf = {
            .speed_mode = LEDC_LOW_SPEED_MODE,
            .duty_resolution = LEDC_TIMER_8_BIT,
            .timer_num = LEDC_TIMER_0,
            .freq_hz = pwm_frequency,
            .clk_cfg = LEDC_AUTO_CLK
        };

        // Configure the LEDC timer
        esp_err_t ret = ledc_timer_config(&timer_conf);
        if (ret != ESP_OK) {
            ESP_LOGE("PwmBacklight", "Failed to configure LEDC timer: %d", ret);
            return;
        }

        // Initialize the LEDC channel
        ledc_channel_config_t channel_conf = {
            .gpio_num = backlight_gpio,
            .speed_mode = LEDC_LOW_SPEED_MODE,
            .channel = LEDC_CHANNEL_0,
            .intr_type = LEDC_INTR_DISABLE,
            .timer_sel = LEDC_TIMER_0,
            .duty = 0,
            .hpoint = 0,
            .flags = {
                .output_invert = invert_output
            }
        };

        // Configure the LEDC channel
        ret = ledc_channel_config(&channel_conf);
        if (ret != ESP_OK) {
            ESP_LOGE("PwmBacklight", "Failed to configure LEDC channel: %d", ret);
            return;
        }

        // Store timer and channel for later use
        ledc_timer = LEDC_TIMER_0;
        ledc_channel = LEDC_CHANNEL_0;
    }

    // Additional methods would typically be here for brightness control
    void set_brightness(uint8_t brightness) {
        ledc_set_duty(LEDC_LOW_SPEED_MODE, ledc_channel, brightness);
        ledc_update_duty(LEDC_LOW_SPEED_MODE, ledc_channel);
    }
};

std::string Board::GenerateUuid() {
    // Generate 16 random bytes using ESP32's hardware random number generator
    uint8_t uuidBytes[16];
    for (int i = 0; i < 16; i++) {
        uuidBytes[i] = esp_random() & 0xFF;
    }

    // Set version bits (4 bits) - UUID version 4
    uuidBytes[6] = (uuidBytes[6] & 0x0F) | 0x40;

    // Set variant bits (2 bits) - RFC 4122 variant
    uuidBytes[8] = (uuidBytes[8] & 0x3F) | 0x80;

    // Format as UUID string: xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx
    char uuidString[37]; // 36 characters + null terminator
    snprintf(uuidString, sizeof(uuidString),
             "%02x%02x%02x%02x-%02x%02x-%02x%02x-%02x%02x-%02x%02x%02x%02x%02x%02x",
             uuidBytes[0], uuidBytes[1], uuidBytes[2], uuidBytes[3],
             uuidBytes[4], uuidBytes[5], uuidBytes[6], uuidBytes[7],
             uuidBytes[8], uuidBytes[9], uuidBytes[10], uuidBytes[11],
             uuidBytes[12], uuidBytes[13], uuidBytes[14], uuidBytes[15]);

    return std::string(uuidString);
}

std::string Board::GetSystemInfoJson() {
    // Create JSON object to hold system information
    JsonDocument doc;

    // Hardware details
    JsonObject hardware = doc["hardware"].to<JsonObject>();

    // Chip model
    #if defined(ESP32)
        hardware["chip_model"] = "ESP32";
    #elif defined(ESP8266)
        hardware["chip_model"] = "ESP8266";
    #else
        hardware["chip_model"] = "Unknown";
    #endif

    // Flash size
    hardware["flash_size_bytes"] = ESP.getFlashChipSize();

    // MAC address
    uint8_t mac[6];
    esp_read_mac(mac, ESP_MAC_WIFI_STA);
    char mac_str[18];
    snprintf(mac_str, sizeof(mac_str), "%02X:%02X:%02X:%02X:%02X:%02X",
             mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);
    hardware["mac_address"] = std::string(mac_str);

    // Application metadata
    JsonObject application = doc["application"].to<JsonObject>();
    application["name"] = APP_NAME;
    application["version"] = APP_VERSION;
    application["compile_time"] = __DATE__ " " __TIME__;

    // Partition table data
    JsonObject partitions = doc["partitions"].to<JsonObject>();
    esp_partition_iterator_t iter = esp_partition_find(ESP_PARTITION_TYPE_APP, ESP_PARTITION_SUBTYPE_APP_FACTORY, NULL);
    if (iter != NULL) {
        const esp_partition_t* part = esp_partition_get(iter);
        partitions["factory_partition_size"] = part->size;
        partitions["factory_partition_address"] = part->address;
    }

    // Runtime information
    JsonObject runtime = doc["runtime"].to<JsonObject>();

    // Minimum free heap size
    runtime["min_free_heap_bytes"] = ESP.getMinFreeHeap();

    // Unique identifiers - UUID generation
    char uuid_str[37];
    uint32_t chipid = ESP.getChipId();
    snprintf(uuid_str, sizeof(uuid_str), "%08X-%04X-%04X-%04X-%08X",
             chipid, 
             (uint16_t)(chipid >> 16),
             (uint16_t)(chipid >> 32),
             (uint16_t)(chipid >> 48),
             (uint32_t)(chipid >> 64));
    runtime["uuid"] = std::string(uuid_str);

    // Additional runtime metrics
    runtime["uptime_seconds"] = millis() / 1000;
    runtime["free_heap_bytes"] = ESP.getFreeHeap();
    runtime["heap_fragmentation_percent"] = (float)(ESP.getMaxFreeBlockSize()) / (float)(ESP.getFreeHeap()) * 100.0f;

    // Serialize JSON to string
    std::string json_string;
    serializeJson(doc, json_string);

    return json_string;
}

Esp32Camera::Esp32Camera(const esp_video_init_config_t &config)
{
    // Initialize camera hardware based on provided configuration
    ESP_LOGI(TAG, "Initializing ESP32 Camera with config");

    // Store configuration
    this->config = config;

    // Initialize V4L2 device handle
    fd = -1;

    // Select appropriate video device interface based on configuration
    std::string device_path;
    switch(config.interface_type) {
        case ESP_VIDEO_INTERFACE_MIPI_CSI:
            device_path = "/dev/video0";
            break;
        case ESP_VIDEO_INTERFACE_DVP:
            device_path = "/dev/video1";
            break;
        case ESP_VIDEO_INTERFACE_JPEG:
            device_path = "/dev/video2";
            break;
        case ESP_VIDEO_INTERFACE_SPI:
            device_path = "/dev/video3";
            break;
        case ESP_VIDEO_INTERFACE_USB_UVC:
            device_path = "/dev/video4";
            break;
        default:
            ESP_LOGE(TAG, "Invalid video interface type");
            return;
    }

    // Open the video device
    fd = open(device_path.c_str(), O_RDWR);
    if (fd < 0) {
        ESP_LOGE(TAG, "Failed to open video device %s: %s", device_path.c_str(), strerror(errno));
        return;
    }

    // Validate device capabilities using V4L2 IOCTL commands
    struct v4l2_capability cap;
    if (ioctl(fd, VIDIOC_QUERYCAP, &cap) < 0) {
        ESP_LOGE(TAG, "Failed to query device capabilities: %s", strerror(errno));
        close(fd);
        fd = -1;
        return;
    }

    // Check if device supports video capture
    if (!(cap.capabilities & V4L2_CAP_VIDEO_CAPTURE)) {
        ESP_LOGE(TAG, "Device does not support video capture");
        close(fd);
        fd = -1;
        return;
    }

    // Check if device supports streaming I/O
    if (!(cap.capabilities & V4L2_CAP_STREAMING)) {
        ESP_LOGE(TAG, "Device does not support streaming I/O");
        close(fd);
        fd = -1;
        return;
    }

    // Set initial pixel format
    struct v4l2_format fmt;
    memset(&fmt, 0, sizeof(fmt));
    fmt.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;

    // Get current format
    if (ioctl(fd, VIDIOC_G_FMT, &fmt) < 0) {
        ESP_LOGW(TAG, "Failed to get current format: %s", strerror(errno));
        // Continue with default format setup
    }

    // Set pixel format based on configuration
    fmt.fmt.pix.pixelformat = config.pixel_format;
    fmt.fmt.pix.width = config.resolution_width;
    fmt.fmt.pix.height = config.resolution_height;
    fmt.fmt.pix.field = V4L2_FIELD_INTERLACED;

    // Set the format
    if (ioctl(fd, VIDIOC_S_FMT, &fmt) < 0) {
        ESP_LOGE(TAG, "Failed to set format: %s", strerror(errno));
        close(fd);
        fd = -1;
        return;
    }

    // Verify that the format was set correctly
    memset(&fmt, 0, sizeof(fmt));
    fmt.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
    if (ioctl(fd, VIDIOC_G_FMT, &fmt) < 0) {
        ESP_LOGE(TAG, "Failed to verify format: %s", strerror(errno));
        close(fd);
        fd = -1;
        return;
    }

    // Validate that requested resolution was accepted
    if (fmt.fmt.pix.width != config.resolution_width || 
        fmt.fmt.pix.height != config.resolution_height) {
        ESP_LOGW(TAG, "Resolution changed from %dx%d to %dx%d",
                 config.resolution_width, config.resolution_height,
                 fmt.fmt.pix.width, fmt.fmt.pix.height);
    }

    // Set buffer queue parameters
    struct v4l2_streamparm stream_params;
    memset(&stream_params, 0, sizeof(stream_params));
    stream_params.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;

    if (ioctl(fd, VIDIOC_G_PARM, &stream_params) < 0) {
        ESP_LOGW(TAG, "Failed to get stream parameters: %s", strerror(errno));
    } else {
        stream_params.parm.capture.timeperframe.numerator = 1;
        stream_params.parm.capture.timeperframe.denominator = config.fps;

        if (ioctl(fd, VIDIOC_S_PARM, &stream_params) < 0) {
            ESP_LOGW(TAG, "Failed to set stream parameters: %s", strerror(errno));
        }
    }

    // Initialize internal state variables
    initialized = true;
    current_pixel_format = config.pixel_format;
    current_resolution_width = fmt.fmt.pix.width;
    current_resolution_height = fmt.fmt.pix.height;

    ESP_LOGI(TAG, "ESP32 Camera initialized successfully");
    ESP_LOGI(TAG, "Resolution: %dx%d, Pixel Format: 0x%x, FPS: %d",
             current_resolution_width, current_resolution_height,
             current_pixel_format, config.fps);
}

bool Esp32Camera::Capture() {
    // Wait for any previous encoding task to complete
    if (encoding_task_handle_ != nullptr) {
        xTaskNotifyWait(0, 0, NULL, portMAX_DELAY);
    }

    // Check if camera is initialized
    if (!is_initialized_) {
        return false;
    }

    // Allocate buffer for the captured frame
    size_t frame_size = width_ * height_ * bytes_per_pixel_;

    // Try to allocate memory in PSRAM first
    uint8_t* frame_buffer = nullptr;
    bool use_psram = psram_available();

    if (use_psram) {
        frame_buffer = (uint8_t*)ps_malloc(frame_size);
        if (frame_buffer == nullptr) {
            // Fallback to regular RAM if PSRAM allocation fails
            frame_buffer = (uint8_t*)malloc(frame_size);
            use_psram = false;
        }
    } else {
        // Allocate in regular RAM only
        frame_buffer = (uint8_t*)malloc(frame_size);
    }

    if (frame_buffer == nullptr) {
        return false; // Memory allocation failed
    }

    // Capture frame from camera hardware
    esp_err_t err = esp_camera_fb_get(&frame_buffer_, &frame_);
    if (err != ESP_OK) {
        free(frame_buffer);
        return false;
    }

    // Perform format conversion if needed
    if (pixel_format_ != PIXFORMAT_JPEG && 
        frame_->format != pixel_format_) {

        // Convert frame to desired format
        switch (pixel_format_) {
            case PIXFORMAT_RGB565:
                // Convert from current format to RGB565
                convert_to_rgb565(frame_buffer, frame_->buf, frame_->len);
                break;
            case PIXFORMAT_GRAYSCALE:
                // Convert from current format to grayscale
                convert_to_grayscale(frame_buffer, frame_->buf, frame_->len);
                break;
            default:
                // Copy directly if no conversion needed
                memcpy(frame_buffer, frame_->buf, frame_->len);
                break;
        }
    } else {
        // Direct copy of frame data
        memcpy(frame_buffer, frame_->buf, frame_->len);
    }

    // Store the captured frame in our internal buffer
    if (captured_frame_.buffer != nullptr) {
        free(captured_frame_.buffer);
    }

    captured_frame_.buffer = frame_buffer;
    captured_frame_.size = frame_->len;
    captured_frame_.width = width_;
    captured_frame_.height = height_;
    captured_frame_.format = pixel_format_;
    captured_frame_.timestamp = millis();

    // Free the framebuffer from camera driver
    esp_camera_fb_return(frame_);

    // Update capture status
    is_frame_captured_ = true;

    return true;
}

esp_err_t Esp32Camera::Explain(const std::string &prompt) {
    // Validate input
    if (prompt.empty()) {
        ESP_LOGE(TAG, "Empty prompt provided");
        return ESP_ERR_INVALID_ARG;
    }

    // Step 1: Capture image from camera
    camera_fb_t *frame_buffer = esp_camera_fb_get();
    if (!frame_buffer) {
        ESP_LOGE(TAG, "Failed to capture image from camera");
        return ESP_FAIL;
    }

    // Step 2: Prepare JPEG encoding in separate thread
    jpeg_data_t jpeg_data = {};
    jpeg_data.data = frame_buffer->buf;
    jpeg_data.length = frame_buffer->len;
    jpeg_data.width = frame_buffer->width;
    jpeg_data.height = frame_buffer->height;

    // Create thread for JPEG encoding
    pthread_t encode_thread;
    pthread_attr_t attr;
    struct sched_param param;

    pthread_attr_init(&attr);
    param.sched_priority = 10;
    pthread_attr_setschedparam(&attr, &param);
    pthread_attr_setstacksize(&attr, 8192);

    if (pthread_create(&encode_thread, &attr, encode_jpeg_thread, &jpeg_data) != 0) {
        ESP_LOGE(TAG, "Failed to create JPEG encoding thread");
        esp_camera_fb_return(frame_buffer);
        return ESP_FAIL;
    }

    // Wait for encoding to complete
    pthread_join(encode_thread, NULL);
    pthread_attr_destroy(&attr);

    // Check if encoding was successful
    if (jpeg_data.encoded_data == nullptr || jpeg_data.encoded_length == 0) {
        ESP_LOGE(TAG, "JPEG encoding failed");
        esp_camera_fb_return(frame_buffer);
        return ESP_FAIL;
    }

    // Step 3: Prepare HTTP request for upload
    std::string url = "https://api.example.com/analyze"; // Replace with actual URL
    std::string boundary = "----WebKitFormBoundary7MA4YWxkTrZu0gW";

    // Build multipart form data
    std::string form_data = "--" + boundary + "\r\n";
    form_data += "Content-Disposition: form-data; name=\"image\"; filename=\"image.jpg\"\r\n";
    form_data += "Content-Type: image/jpeg\r\n\r\n";

    // Add JPEG data
    form_data.append((char*)jpeg_data.encoded_data, jpeg_data.encoded_length);
    form_data += "\r\n--" + boundary + "\r\n";
    form_data += "Content-Disposition: form-data; name=\"prompt\"\r\n\r\n";
    form_data += prompt + "\r\n";
    form_data += "--" + boundary + "--\r\n";

    // Step 4: Set up HTTP headers
    httpd_req_t *req = nullptr; // This would typically be handled by HTTP server context

    // Create HTTP client configuration
    http_client_config_t config = {
        .url = url.c_str(),
        .method = HTTP_METHOD_POST,
        .timeout_ms = 10000,
        .disable_auto_redirect = false,
        .max_redirection_count = 3,
    };

    // Step 5: Send HTTP POST request
    esp_http_client_handle_t client = esp_http_client_init(&config);

    if (!client) {
        ESP_LOGE(TAG, "Failed to initialize HTTP client");
        free(jpeg_data.encoded_data);
        esp_camera_fb_return(frame_buffer);
        return ESP_FAIL;
    }

    // Set headers
    esp_http_client_set_header(client, "Content-Type", ("multipart/form-data; boundary=" + boundary).c_str());
    esp_http_client_set_header(client, "X-Device-ID", device_id_.c_str());
    esp_http_client_set_header(client, "Authorization", ("Bearer " + auth_token_).c_str());
    esp_http_client_set_header(client, "User-Agent", "ESP32-Camera-Analyzer/1.0");

    // Set POST data
    esp_http_client_set_post_field(client, form_data.c_str(), form_data.length());

    // Perform the request
    esp_err_t err = esp_http_client_perform(client);

    if (err != ESP_OK) {
        ESP_LOGE(TAG, "HTTP POST request failed: %s", esp_err_to_name(err));
        esp_http_client_cleanup(client);
        free(jpeg_data.encoded_data);
        esp_camera_fb_return(frame_buffer);
        return err;
    }

    int status_code = esp_http_client_get_status_code(client);
    if (status_code != 200) {
        ESP_LOGE(TAG, "Server returned error status: %d", status_code);
        esp_http_client_cleanup(client);
        free(jpeg_data.encoded_data);
        esp_camera_fb_return(frame_buffer);
        return ESP_FAIL;
    }

    // Clean up resources
    esp_http_client_cleanup(client);
    free(jpeg_data.encoded_data);
    esp_camera_fb_return(frame_buffer);

    ESP_LOGI(TAG, "Image successfully uploaded and analyzed");
    return ESP_OK;
}

