void StartNetwork() {
    // Initialize WiFi manager with predefined SSID prefix and language
    WiFiManager wifiManager;
    wifiManager.setConfigPortalSSID("ESP32_CONFIG");
    wifiManager.setConfigPortalPassword("123456789");

    // Set up unified event callback to handle various WiFi events
    wifiManager.setEventCallback([](WiFiEvent_t event) {
        switch(event) {
            case SYSTEM_EVENT_WIFI_READY:
                Serial.println("WiFi interface ready");
                break;
            case SYSTEM_EVENT_SCAN_DONE:
                Serial.println("Completed scanning for access points");
                break;
            case SYSTEM_EVENT_STA_START:
                Serial.println("Station started");
                break;
            case SYSTEM_EVENT_STA_STOP:
                Serial.println("Station stopped");
                break;
            case SYSTEM_EVENT_STA_CONNECTED:
                Serial.println("Connected to access point");
                break;
            case SYSTEM_EVENT_STA_DISCONNECTED:
                Serial.println("Disconnected from access point");
                // Attempt to reconnect
                WiFi.reconnect();
                break;
            case SYSTEM_EVENT_STA_AUTHMODE_CHANGE:
                Serial.println("Authentication mode of access point has changed");
                break;
            case SYSTEM_EVENT_STA_GOT_IP:
                Serial.println("Got IP address");
                Serial.println(WiFi.localIP());
                break;
            case SYSTEM_EVENT_STA_LOST_IP:
                Serial.println("Lost IP address");
                break;
            case SYSTEM_EVENT_WPS_ER_SUCCESS:
                Serial.println("WiFi Protected Setup (WPS) succeeded");
                break;
            case SYSTEM_EVENT_WPS_ER_FAILED:
                Serial.println("WiFi Protected Setup (WPS) failed");
                break;
            case SYSTEM_EVENT_WPS_ER_TIMEOUT:
                Serial.println("WiFi Protected Setup (WPS) timeout");
                break;
            case SYSTEM_EVENT_WPS_ER_PIN:
                Serial.println("WiFi Protected Setup (WPS) pin code");
                break;
            case SYSTEM_EVENT_AP_START:
                Serial.println("Access Point started");
                break;
            case SYSTEM_EVENT_AP_STOP:
                Serial.println("Access Point stopped");
                break;
            case SYSTEM_EVENT_AP_STACONNECTED:
                Serial.println("A station connected to Access Point");
                break;
            case SYSTEM_EVENT_AP_STADISCONNECTED:
                Serial.println("A station disconnected from Access Point");
                break;
            case SYSTEM_EVENT_AP_PROBEREQRECVED:
                Serial.println("Received probe request");
                break;
            default:
                Serial.println("Unknown WiFi event occurred");
                break;
        }
    });

    // Attempt to establish WiFi connection
    bool connected = wifiManager.autoConnect();

    // If connection fails, enter configuration mode
    if (!connected) {
        Serial.println("Failed to connect to WiFi, entering configuration mode...");
        // Force configuration mode by clearing saved credentials
        wifiManager.resetSettings();
        // Enter configuration mode with custom parameters
        wifiManager.setConfigPortalTimeout(180); // 3 minutes timeout
        wifiManager.setAPCallback([](WiFiManager *myWiFiManager) {
            Serial.println("Entered configuration mode");
            Serial.println(myWiFiManager->getConfigPortalSSID());
        });

        // Start configuration portal
        if (wifiManager.startConfigPortal()) {
            Serial.println("Configuration portal successful");
        } else {
            Serial.println("Configuration portal failed");
        }
    } else {
        Serial.println("Successfully connected to WiFi network");
        Serial.println(WiFi.SSID());
        Serial.println(WiFi.localIP());
    }
}

void OnNetworkEvent(NetworkEvent event, const std::string& eventData)
{
    // Handle different network events
    switch (event)
    {
        case NetworkEvent::Connected:
            // Set connected flag
            is_connected_ = true;

            // Stop any running timers
            if (reconnect_timer_)
            {
                reconnect_timer_->Stop();
            }

            // Release provisioning resources when connected
            if (provisioning_resource_)
            {
                provisioning_resource_->Release();
                provisioning_resource_ = nullptr;
            }

            // Reset connection attempt counter
            connection_attempts_ = 0;

            // Notify external callback if set
            if (network_callback_)
            {
                network_callback_(event, eventData);
            }
            break;

        case NetworkEvent::Disconnected:
            // Clear connected flag
            is_connected_ = false;

            // Stop any running timers
            if (reconnect_timer_)
            {
                reconnect_timer_->Stop();
            }

            // Start reconnection timer
            if (reconnect_timer_)
            {
                reconnect_timer_->Start(5000); // 5 second retry interval
            }

            // Notify external callback if set
            if (network_callback_)
            {
                network_callback_(event, eventData);
            }
            break;

        case NetworkEvent::ScanComplete:
            // Handle scan completion
            scan_complete_ = true;

            // Notify external callback if set
            if (network_callback_)
            {
                network_callback_(event, eventData);
            }
            break;

        case NetworkEvent::ConfigModeChanged:
            // Handle configuration mode change
            if (eventData == "enter")
            {
                // Entering configuration mode
                is_config_mode_ = true;

                // Stop any active connections
                if (is_connected_)
                {
                    // Disconnect from current network
                    Disconnect();
                }

                // Stop reconnection attempts
                if (reconnect_timer_)
                {
                    reconnect_timer_->Stop();
                }
            }
            else if (eventData == "exit")
            {
                // Exiting configuration mode
                is_config_mode_ = false;

                // Trigger reconnection attempt
                if (should_reconnect_on_exit_config_)
                {
                    Reconnect();
                }
            }

            // Notify external callback if set
            if (network_callback_)
            {
                network_callback_(event, eventData);
            }
            break;

        default:
            // Handle unknown events
            if (network_callback_)
            {
                network_callback_(event, eventData);
            }
            break;
    }
}

void StartWifiConfigMode() {
    // Set device state to configuring mode
    SetDeviceState(DEVICE_STATE_CONFIGURING);

    // Enable provisioning method based on compile-time flags
#ifdef ENABLE_HOTSPOT_CONFIG
    // Start hotspot configuration with user prompts
    StartHotspotConfig();
    ShowUserPrompt("Connect to WiFi network: DeviceConfig_Hotspot");
    ShowUserPrompt("Open browser and navigate to: 192.168.4.1");
#elif defined(ENABLE_BLE_PROVISIONING)
    // Enable Bluetooth Low Energy provisioning via Blufi
    StartBLEProvisioning();
    ShowUserPrompt("Pair with device via Bluetooth");
    ShowUserPrompt("Use mobile app to configure WiFi settings");
#elif defined(ENABLE_AUDIO_PROVISIONING)
    // Enable acoustic provisioning through audio input
    StartAudioProvisioning();
    ShowUserPrompt("Speak WiFi credentials through microphone");
    ShowUserPrompt("Device will listen for audio configuration");
#else
    // Default fallback - enable hotspot if no specific provisioning method is defined
    StartHotspotConfig();
    ShowUserPrompt("Connect to WiFi network: DeviceConfig_Default");
#endif

    // Start necessary services for configuration
    StartWiFiService();
    StartConfigurationServer();

    // Provide visual feedback to user
    SetLEDStatus(LED_STATUS_CONFIGURING);

    // Log configuration start event
    LogEvent(EVENT_WIFI_CONFIG_START);
}

void EnterWifiConfigMode()
{
    // Validate current device state to prevent conflicts
    if (IsDeviceInConfigMode() || IsDeviceInUpdateMode()) {
        // Device already in a conflicting mode, return early
        return;
    }

    // Display notification to user about entering configuration mode
    DisplayNotification("Entering Wi-Fi Configuration Mode...");

    // Gracefully shutdown active audio/communication processes
    StopAudioPlayback();
    DisconnectBluetooth();
    PauseNetworkOperations();

    // Wait for processes to fully terminate
    DelayMilliseconds(500);

    // Reset any active communication protocols
    ResetCommunicationChannels();

    // Update device state to configuration mode
    SetDeviceState(DEVICE_STATE_CONFIG_MODE);

    // Initialize Wi-Fi configuration process
    InitializeWifiConfig();

    // Start Wi-Fi configuration service
    StartWifiConfigurationService();

    // Notify system components of mode change
    NotifySystemOfModeChange(MODE_WIFI_CONFIG);
}

std::string WifiBoard::GetDeviceStatusJson() {
    // Create JSON object to hold device status
    json statusJson;

    // Get audio speaker volume
    int audioVolume = GetAudioVolume();
    statusJson["audio"] = {
        {"volume", audioVolume}
    };

    // Get screen brightness and theme
    int screenBrightness = GetScreenBrightness();
    std::string screenTheme = GetScreenTheme();
    statusJson["display"] = {
        {"brightness", screenBrightness},
        {"theme", screenTheme}
    };

    // Get battery level and charging state
    int batteryLevel = GetBatteryLevel();
    bool isCharging = IsBatteryCharging();
    statusJson["battery"] = {
        {"level", batteryLevel},
        {"charging", isCharging}
    };

    // Get WiFi network details
    std::string wifiSsid = GetWiFiSSID();
    int wifiSignalStrength = GetWiFiSignalStrength();
    statusJson["wifi"] = {
        {"ssid", wifiSsid},
        {"signal_strength", wifiSignalStrength}
    };

    // Get chip temperature
    float chipTemperature = GetChipTemperature();
    statusJson["temperature"] = {
        {"chip", chipTemperature}
    };

    // Convert JSON object to string
    return statusJson.dump();
}

void InitializeLcdThemes()
{
    // Create light theme configuration
    Theme lightTheme;
    lightTheme.name = "Light";
    lightTheme.backgroundColor = 0xFFFFFF;  // White background
    lightTheme.textColor = 0x000000;       // Black text
    lightTheme.chatBubbleColor = 0xE0E0E0; // Light gray bubbles
    lightTheme.chatBubbleTextColor = 0x000000; // Black text in bubbles
    lightTheme.fontFamily = "Arial";
    lightTheme.fontSize = 12;
    lightTheme.fontBold = false;

    // Create dark theme configuration
    Theme darkTheme;
    darkTheme.name = "Dark";
    darkTheme.backgroundColor = 0x000000;  // Black background
    darkTheme.textColor = 0xFFFFFF;       // White text
    darkTheme.chatBubbleColor = 0x303030; // Dark gray bubbles
    darkTheme.chatBubbleTextColor = 0xFFFFFF; // White text in bubbles
    darkTheme.fontFamily = "Arial";
    darkTheme.fontSize = 12;
    darkTheme.fontBold = false;

    // Register themes with theme manager
    ThemeManager& themeManager = ThemeManager::getInstance();

    // Register light theme
