MipiLcdDisplay::MipiLcdDisplay(esp_lcd_panel_io_handle_t io_handle, 
                              esp_lcd_panel_handle_t panel_handle,
                              int width, int height, 
                              int rotation, int offset_x, int offset_y,
                              bool mirror_x, bool mirror_y, bool swap_xy)
{
    // Initialize LVGL display descriptor
    lv_disp_draw_buf_init(&draw_buffer, buffer_1, buffer_2, width * 10);

    // Configure display properties
    disp_drv.hor_res = width;
    disp_drv.ver_res = height;
    disp_drv.flush_cb = lcd_flush_callback;
    disp_drv.draw_buf = &draw_buffer;
    disp_drv.user_data = this;

    // Set rotation and mirroring
    disp_drv.rotated = rotation;
    disp_drv.mirror_x = mirror_x;
    disp_drv.mirror_y = mirror_y;
    disp_drv.swap_xy = swap_xy;

    // Set offset values
    disp_drv.offset_x = offset_x;
    disp_drv.offset_y = offset_y;

    // Initialize the display driver
    lv_disp_drv_register(&disp_drv);

    // Store panel handles for later use
    this->io_handle = io_handle;
    this->panel_handle = panel_handle;

    // Initialize display with provided parameters
    esp_err_t err = ESP_OK;

    // Configure panel with the provided handles
    if (panel_handle != NULL) {
        // Set panel orientation based on rotation parameter
        switch (rotation) {
            case 0:
                err = esp_lcd_panel_swap_xy(panel_handle, false);
                err |= esp_lcd_panel_mirror(panel_handle, false, false);
                break;
            case 1:
                err = esp_lcd_panel_swap_xy(panel_handle, true);
                err |= esp_lcd_panel_mirror(panel_handle, false, false);
                break;
            case 2:
                err = esp_lcd_panel_swap_xy(panel_handle, false);
                err |= esp_lcd_panel_mirror(panel_handle, true, true);
                break;
            case 3:
                err = esp_lcd_panel_swap_xy(panel_handle, true);
                err |= esp_lcd_panel_mirror(panel_handle, true, true);
                break;
            default:
                err = esp_lcd_panel_swap_xy(panel_handle, false);
                err |= esp_lcd_panel_mirror(panel_handle, false, false);
                break;
        }

        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to configure panel orientation: %s", esp_err_to_name(err));
            return;
        }
    }

    // Initialize LVGL
    lv_init();

    // Set up the display interface
    lv_disp_drv_t *disp_drv_ptr = &disp_drv;
    disp_drv_ptr->hor_res = width;
    disp_drv_ptr->ver_res = height;

    // Register the display driver with LVGL
    lv_disp_drv_register(disp_drv_ptr);

    // Initialize buffers
    size_t buffer_size = width * 10 * sizeof(lv_color_t);
    buffer_1 = (lv_color_t *)heap_caps_malloc(buffer_size, MALLOC_CAP_DMA);
    buffer_2 = (lv_color_t *)heap_caps_malloc(buffer_size, MALLOC_CAP_DMA);

    if (!buffer_1 || !buffer_2) {
        ESP_LOGE(TAG, "Failed to allocate display buffers");
        if (buffer_1) heap_caps_free(buffer_1);
        if (buffer_2) heap_caps_free(buffer_2);
        return;
    }

    // Initialize draw buffer
    lv_disp_draw_buf_init(&draw_buffer, buffer_1, buffer_2, width * 10);

    // Setup UI after successful display configuration
    setup_ui();

    ESP_LOGI(TAG, "MIPI LCD Display initialized successfully with resolution %dx%d", width, height);
}

LcdDisplay::~LcdDisplay()
{
    // Stop and delete the GIF controller
    if (gifController != nullptr)
    {
        gifController->stop();
        delete gifController;
        gifController = nullptr;
    }

    // Remove all UI elements from the screen
    // Remove images
    while (!images.empty())
    {
        auto image = images.back();
        removeElement(image);
        delete image;
        images.pop_back();
    }

    // Remove labels
    while (!labels.empty())
    {
        auto label = labels.back();
        removeElement(label);
        delete label;
        labels.pop_back();
    }

    // Remove progress bars
    while (!progressBars.empty())
    {
        auto bar = progressBars.back();
        removeElement(bar);
        delete bar;
        progressBars.pop_back();
    }

    // Remove containers
    while (!containers.empty())
    {
        auto container = containers.back();
        removeElement(container);
        delete container;
        containers.pop_back();
    }

    // Remove any remaining UI elements
    removeAllElements();

    // Cancel and delete any active timers
    for (auto& timer : timers)
    {
        if (timer != nullptr)
        {
            timer->cancel();
            delete timer;
            timer = nullptr;
        }
    }
    timers.clear();

    // Deallocate the underlying LCD panel
    if (lcdPanel != nullptr)
    {
        delete lcdPanel;
        lcdPanel = nullptr;
    }

    // Deallocate the panel IO drivers
    if (panelIoDriver != nullptr)
    {
        delete panelIoDriver;
        panelIoDriver = nullptr;
    }

    // Clear any remaining references
    gifController = nullptr;
    lcdPanel = nullptr;
    panelIoDriver = nullptr;
}

