void LcdDisplay::SetChatMessage(const char* message, const char* role)
{
    // Check if message is empty or null
    if (!message || strlen(message) == 0) {
        return;
    }

    // Remove oldest message if we've reached maximum history
    if (m_messageHistory.size() >= MAX_MESSAGE_HISTORY) {
        m_messageHistory.erase(m_messageHistory.begin());
    }

    // Create new message entry
    MessageEntry newMessage;
    newMessage.content = std::string(message);
    newMessage.role = std::string(role);
    newMessage.timestamp = std::chrono::steady_clock::now();

    // Add to history
    m_messageHistory.push_back(newMessage);

    // Handle system messages differently
    bool isSystemMessage = (strcmp(role, "system") == 0);

    // Clear previous display content
    ClearScreen();

    // Calculate display parameters based on message content and role
    int bubbleWidth = CalculateBubbleWidth(message);
    int bubbleHeight = CalculateBubbleHeight(message);
    Position bubblePosition = CalculateBubblePosition(bubbleWidth, bubbleHeight);

    // Draw message bubble with appropriate styling
    if (isSystemMessage) {
        // System messages get special styling
        DrawStyledBubble(bubblePosition.x, bubblePosition.y, 
                        bubbleWidth, bubbleHeight, 
                        SYSTEM_BUBBLE_COLOR, SYSTEM_BORDER_COLOR);
    } else {
        // Regular messages get different styling
        DrawStyledBubble(bubblePosition.x, bubblePosition.y, 
                        bubbleWidth, bubbleHeight, 
                        USER_BUBBLE_COLOR, USER_BORDER_COLOR);
    }

    // Draw message text inside bubble
    DrawTextInsideBubble(message, bubblePosition.x, bubblePosition.y, 
                        bubbleWidth, bubbleHeight);

    // Hide AI logo for non-system messages
    if (!isSystemMessage) {
        HideAiLogo();
    } else {
        // Show AI logo for system messages if needed
        ShowAiLogo();
    }

    // Update display
    RefreshDisplay();
}

void SetPreviewImage(std::unique_ptr<LvglImage> image)
{
    // Check if the image is valid
    if (!image || !image->IsValid())
    {
        LV_LOG_WARN("Invalid image provided to SetPreviewImage");
        return;
    }

    // Get image dimensions
    int32_t image_width = image->GetWidth();
    int32_t image_height = image->GetHeight();

    // Define maximum dimensions for preview
    const int32_t MAX_PREVIEW_WIDTH = 240;
    const int32_t MAX_PREVIEW_HEIGHT = 160;

    // Handle invalid dimensions by logging warning and using defaults
    if (image_width <= 0 || image_height <= 0)
    {
        LV_LOG_WARN("Invalid image dimensions (%d x %d), using default sizes", 
                   image_width, image_height);
        image_width = MAX_PREVIEW_WIDTH;
        image_height = MAX_PREVIEW_HEIGHT;
    }

    // Calculate scaling factors to fit within maximum dimensions
    float width_scale = (float)MAX_PREVIEW_WIDTH / (float)image_width;
    float height_scale = (float)MAX_PREVIEW_HEIGHT / (float)image_height;

    // Use the smaller scale to ensure the image fits within both dimensions
    float scale_factor = std::min(width_scale, height_scale);

    // Calculate scaled dimensions
    int32_t scaled_width = (int32_t)(image_width * scale_factor);
    int32_t scaled_height = (int32_t)(image_height * scale_factor);

    // Create message bubble container with appropriate size
    lv_obj_t* bubble_container = lv_obj_create(lv_scr_act());
    lv_obj_set_size(bubble_container, scaled_width + 20, scaled_height + 20);
    lv_obj_align(bubble_container, LV_ALIGN_CENTER, 0, 0);

    // Set background style for the bubble
    lv_obj_set_style_bg_color(bubble_container, lv_color_hex(0xF0F0F0), 0);
    lv_obj_set_style_bg_opa(bubble_container, LV_OPA_50, 0);
    lv_obj_set_style_border_width(bubble_container, 1, 0);
    lv_obj_set_style_border_color(bubble_container, lv_color_hex(0x808080), 0);
    lv_obj_set_style_radius(bubble_container, 8, 0);

    // Create image object within the bubble container
    lv_obj_t* image_obj = lv_img_create(bubble_container);
    lv_img_set_src(image_obj, image.get());

    // Position the image within the bubble
    lv_obj_align(image_obj, LV_ALIGN_CENTER, 0, 0);

    // Set the image size to match scaled dimensions
    lv_img_set_zoom(image_obj, 256); // 256 is normal zoom level

    // Set the image as content of the bubble container
    lv_obj_add_flag(bubble_container, LV_OBJ_FLAG_USER_1);

    // Store the image pointer in the container for cleanup
    lv_obj_set_user_data(bubble_container, image.release());

    // Add deletion callback to clean up the image when container is deleted
    lv_obj_add_event_cb(bubble_container, [](lv_event_t* e) {
        lv_obj_t* obj = lv_event_get_target(e);
        void* user_data = lv_obj_get_user_data(obj);
        if (user_data) {
            LvglImage* img = static_cast<LvglImage*>(user_data);
            delete img;
        }
    }, LV_EVENT_DELETE, nullptr);
}

