void LcdDisplay::SetChatMessage(const char* message, const char* role)
{
    // Check if message is empty or null
    if (!message || strlen(message) == 0) {
        return;
    }

    // Remove oldest message if we've reached maximum history
    if (m_messageHistory.size() >= MAX_MESSAGE_HISTORY) {
        m_messageHistory.erase(m_messageHistory.begin());
    }

    // Create new message entry
    MessageEntry newMessage;
    newMessage.content = std::string(message);
    newMessage.role = std::string(role);
    newMessage.timestamp = std::chrono::steady_clock::now();

    // Add to history
    m_messageHistory.push_back(newMessage);

    // Handle system messages differently
    bool isSystemMessage = (strcmp(role, "system") == 0);

    // Clear previous display content
    ClearScreen();

    // Calculate display parameters based on message content and role
    int bubbleWidth = CalculateBubbleWidth(message);
    int bubbleHeight = CalculateBubbleHeight(message);
    Position bubblePosition = CalculateBubblePosition(bubbleWidth, bubbleHeight);

    // Draw message bubble with appropriate styling
    if (isSystemMessage) {
        // System messages get special styling
        DrawStyledBubble(bubblePosition.x, bubblePosition.y, 
                        bubbleWidth, bubbleHeight, 
                        SYSTEM_BUBBLE_COLOR, SYSTEM_BORDER_COLOR);
    } else {
        // Regular messages get different styling
        DrawStyledBubble(bubblePosition.x, bubblePosition.y, 
                        bubbleWidth, bubbleHeight, 
                        USER_BUBBLE_COLOR, USER_BORDER_COLOR);
    }

    // Draw message text inside bubble
    DrawTextInsideBubble(message, bubblePosition.x, bubblePosition.y, 
                        bubbleWidth, bubbleHeight);

    // Hide AI logo for non-system messages
    if (!isSystemMessage) {
        HideAiLogo();
    } else {
        // Show AI logo for system messages if needed
        ShowAiLogo();
    }

    // Update display
    RefreshDisplay();
}

void LcdDisplay::SetEmotion(const char *emotion)
{
    // Check if emotion parameter is valid
    if (emotion == nullptr) {
        return;
    }

    // Handle neutral emotion with WeChat-style messaging enabled
    if (strcmp(emotion, "neutral") == 0 && m_weChatStyleEnabled) {
        // Hide the emotion display entirely
        HideEmotionDisplay();
        return;
    }

    // Check if we need to load a new asset
    bool shouldLoadAsset = true;

    // If current emotion is the same as requested, check if animation needs refresh
    if (m_currentEmotion != nullptr && strcmp(m_currentEmotion, emotion) == 0) {
        // If it's an animated GIF, we might need to restart animation
        if (IsGifEmotion(emotion)) {
            // Restart GIF animation
            RestartGifAnimation();
            return;
        } else {
            // Static image - no reload needed
            shouldLoadAsset = false;
        }
    }

    // Load the emotion asset if needed
    if (shouldLoadAsset) {
        // Free previous asset if exists
        if (m_currentEmotion != nullptr) {
            FreeEmotionAsset(m_currentEmotion);
        }

        // Load new emotion asset
        if (LoadEmotionAsset(emotion)) {
            // Update current emotion
            m_currentEmotion = emotion;
        } else {
            // Failed to load asset, fallback to default neutral
            m_currentEmotion = "neutral";
            LoadEmotionAsset("neutral");
        }
    }

    // Render the emotion to display
    if (IsGifEmotion(emotion)) {
        // Handle GIF animation
        StartGifAnimation();
    } else {
        // Handle static image
        RenderStaticEmotion();
    }

    // Ensure display is visible
    ShowEmotionDisplay();

    // Update timestamp for emotion display
    m_lastEmotionUpdateTime = GetSystemTime();
}

void LcdDisplay::SetTheme(Theme* theme)
{
    // Acquire display lock for thread safety
    std::lock_guard<std::mutex> lock(displayMutex);

    // Validate input parameter
    if (theme == nullptr)
    {
        return;
    }

    // Apply font settings from theme
    currentFont = theme->GetFont();
    fontSize = theme->GetFontSize();

    // Apply color scheme
    textColor = theme->GetTextColor();
    backgroundColor = theme->GetBackgroundColor();
    highlightColor = theme->GetHighlightColor();
    borderColor = theme->GetBorderColor();

    // Apply background image if available
    if (theme->HasBackgroundImage())
    {
        backgroundImage = theme->GetBackgroundImage();
        hasBackgroundImage = true;
    }
    else
    {
        hasBackgroundImage = false;
        backgroundImage = nullptr;
    }

    // Apply style settings for UI elements
    labelStyle = theme->GetLabelStyle();
    statusBarStyle = theme->GetStatusBarStyle();
    messageBubbleStyle = theme->GetMessageBubbleStyle();

    // Update font metrics based on current font size
    UpdateFontMetrics(fontSize);

    // Apply semi-transparent overlays if specified
    if (theme->HasOverlay())
    {
        overlayAlpha = theme->GetOverlayAlpha();
        overlayColor = theme->GetOverlayColor();
        useOverlay = true;
    }
    else
    {
        useOverlay = false;
    }

    // Update all UI elements with new theme settings
    UpdateAllLabels();
    UpdateStatusBar();
    UpdateMessageBubbles();

    // Trigger display refresh to apply changes
    RefreshDisplay();
}

esp_err_t SingleLed(gpio_num_t gpio_pin)
{
    // Initialize RMT peripheral for WS2812 communication
    rmt_config_t rmt_config = {
        .rmt_mode = RMT_MODE_TX,
        .channel = RMT_CHANNEL_0,
        .gpio_num = gpio_pin,
        .clk_div = 80,  // 80MHz / 80 = 1MHz clock (1us per tick)
        .mem_block_num = 1,
        .tx_config = {
            .carrier_en = false,
            .idle_level = RMT_IDLE_LEVEL_LOW,
            .idle_output_en = true,
        }
    };

    // Configure RMT channel
    esp_err_t ret = rmt_config(&rmt_config);
    if (ret != ESP_OK) {
        return ret;
    }

    // Install RMT driver
    ret = rmt_driver_install(rmt_config.channel, 0, 0);
    if (ret != ESP_OK) {
        return ret;
    }

    // Initialize LED state - turn off initially
    // Create RMT data for OFF state (0x00000000 for RGB=0,0,0)
    rmt_data_t led_off_data[24];
    for (int i = 0; i < 24; i++) {
        led_off_data[i] = (rmt_data_t){.level0 = 0, .duration0 = 1, .level1 = 0, .duration1 = 1};
    }

    // Send OFF command to clear LED
    ret = rmt_write_items(rmt_config.channel, led_off_data, 24, true);
    if (ret != ESP_OK) {
        return ret;
    }

    // Setup timer for blinking functionality
    // Using timer group 0, timer 0
    timer_config_t timer_config = {
        .divider = 80,  // 1MHz timer clock
        .counter_dir = TIMER_COUNT_UP,
        .counter_en = TIMER_PAUSE,
        .alarm_en = TIMER_ALARM_EN,
        .auto_reload = true,
    };

    ret = timer_init(TIMER_GROUP_0, TIMER_0, &timer_config);
    if (ret != ESP_OK) {
        return ret;
    }

    // Set alarm value for 1 second period (1000000 ticks at 1MHz)
    ret = timer_set_alarm_value(TIMER_GROUP_0, TIMER_0, 1000000);
    if (ret != ESP_OK) {
        return ret;
    }

    // Enable timer interrupt
    ret = timer_enable_intr(TIMER_GROUP_0, TIMER_0);
    if (ret != ESP_OK) {
        return ret;
    }

    // Register timer callback for blinking control
    ret = timer_isr_register(TIMER_GROUP_0, TIMER_0, NULL, 0, NULL);
    if (ret != ESP_OK) {
        return ret;
    }

    return ESP_OK;
}

void SingleLed::OnStateChanged()
{
    // Get current device state
    DeviceState currentState = GetDeviceState();

    // Turn off LED first to ensure clean state
    led->Off();

    switch(currentState)
    {
        case DeviceState::Starting:
            // Blue solid light during startup
            led->SetColor(Color::Blue);
            led->SetBrightness(100);
            led->On();
            break;

        case DeviceState::WiFiConfig:
            // Yellow blinking pattern for Wi-Fi configuration
            led->SetColor(Color::Yellow);
            led->SetBlinkPattern(BlinkPattern::FastBlink);
            led->On();
            break;

        case DeviceState::Idle:
            // Green solid light when idle
            led->SetColor(Color::Green);
            led->SetBrightness(50);
            led->On();
            break;

        case DeviceState::Connecting:
            // Cyan blinking for connection process
            led->SetColor(Color::Cyan);
            led->SetBlinkPattern(BlinkPattern::MediumBlink);
            led->On();
            break;

        case DeviceState::Listening:
            // Purple steady light when listening
            led->SetColor(Color::Purple);
            led->SetBrightness(75);
            led->On();
            break;

        case DeviceState::Speaking:
            // Red blinking for speaking activity
            led->SetColor(Color::Red);
            led->SetBlinkPattern(BlinkPattern::SlowBlink);
            led->On();
            break;

        case DeviceState::Upgrading:
            // Orange blinking for firmware upgrade
            led->SetColor(Color::Orange);
            led->SetBlinkPattern(BlinkPattern::FastBlink);
            led->On();
            break;

        case DeviceState::Activating:
            // White fast blinking for activation process
            led->SetColor(Color::White);
            led->SetBlinkPattern(BlinkPattern::VeryFastBlink);
            led->On();
            break;

        default:
            // Default: Off for unknown states
            led->Off();
            break;
    }
}

MqttProtocol::MqttProtocol() {
    // Initialize the MQTT communication layer
    // Set up event group for synchronization
    mqttEventGroup = xEventGroupCreate();
    if (mqttEventGroup == NULL) {
        // Handle error - failed to create event group
        return;
    }

    // Initialize MQTT client structure
    memset(&mqttClient, 0, sizeof(mqttClient));

    // Set default values for MQTT configuration
    mqttClient.keepAliveInterval = MQTT_KEEP_ALIVE_INTERVAL;
    mqttClient.cleanSession = true;
    mqttClient.username = NULL;
    mqttClient.password = NULL;

    // Initialize the reconnect timer
    reconnectTimer = xTimerCreate(
        "MQTT_Reconnect_Timer",
        pdMS_TO_TICKS(MQTT_RECONNECT_INTERVAL_MS),
        pdTRUE,           // Auto-reload
        this,             // Timer ID
        reconnectTimerCallback
    );

    if (reconnectTimer == NULL) {
        // Handle error - failed to create timer
        vEventGroupDelete(mqttEventGroup);
        return;
    }

    // Initialize connection state
    connectionState = MQTT_DISCONNECTED;

    // Initialize mutex for thread safety
    mqttMutex = xSemaphoreCreateMutex();
    if (mqttMutex == NULL) {
        // Handle error - failed to create mutex
        xTimerDelete(reconnectTimer, 0);
        vEventGroupDelete(mqttEventGroup);
        return;
    }

    // Initialize message queue for outgoing messages
    mqttMessageQueue = xQueueCreate(MQTT_MESSAGE_QUEUE_SIZE, sizeof(MqttMessage));
    if (mqttMessageQueue == NULL) {
        // Handle error - failed to create queue
        vSemaphoreDelete(mqttMutex);
        xTimerDelete(reconnectTimer, 0);
        vEventGroupDelete(mqttEventGroup);
        return;
    }

    // Initialize subscription tracking
    memset(subscriptionList, 0, sizeof(subscriptionList));
    subscriptionCount = 0;

    // Set up MQTT network interface (assuming it's configured elsewhere)
    mqttNetworkInterface = NULL;

    // Initialize retry counter
    reconnectAttempts = 0;

    // Set initial state to disconnected
    xEventGroupSetBits(mqttEventGroup, MQTT_STATE_DISCONNECTED);
}

bool StartMqttClient(bool enableDebug = false)
{
    // Initialize MQTT client with configuration settings
    if (!mqttClient.begin(mqttBrokerEndpoint, mqttPort, &networkClient))
    {
        if (enableDebug)
        {
            Serial.println("Failed to initialize MQTT client");
        }
        return false;
    }

    // Set up connection event handler
    mqttClient.onConnect([](bool sessionPresent) {
        if (enableDebug)
        {
            Serial.println("MQTT connected");
        }

        // Subscribe to required topics
        mqttClient.subscribe("audio/control/#");
        mqttClient.subscribe("session/updates/#");

        // Handle session management
        if (!sessionPresent)
        {
            // New session - send initial connection message
            String connectMsg = "{\"type\":\"connected\",\"timestamp\":" + String(millis()) + "}";
            mqttClient.publish("client/status", connectMsg.c_str());
        }
        else
        {
            // Reconnected to existing session
            if (enableDebug)
            {
                Serial.println("Reconnected to existing session");
            }
        }
    });

    // Set up disconnection event handler
    mqttClient.onDisconnect([](AsyncMqttClientDisconnectReason reason) {
        if (enableDebug)
        {
            Serial.print("MQTT disconnected: ");
            switch (reason)
            {
                case AsyncMqttClientDisconnectReason::TCP_DISCONNECTED:
                    Serial.println("TCP_DISCONNECTED");
                    break;
                case AsyncMqttClientDisconnectReason::MQTT_UNACCEPTABLE_PROTOCOL_VERSION:
                    Serial.println("MQTT_UNACCEPTABLE_PROTOCOL_VERSION");
                    break;
                case AsyncMqttClientDisconnectReason::MQTT_IDENTIFIER_REJECTED:
                    Serial.println("MQTT_IDENTIFIER_REJECTED");
                    break;
                case AsyncMqttClientDisconnectReason::MQTT_SERVER_UNAVAILABLE:
                    Serial.println("MQTT_SERVER_UNAVAILABLE");
                    break;
                case AsyncMqttClientDisconnectReason::MQTT_MALFORMED_CREDENTIALS:
                    Serial.println("MQTT_MALFORMED_CREDENTIALS");
                    break;
                case AsyncMqttClientDisconnectReason::MQTT_NOT_AUTHORIZED:
                    Serial.println("MQTT_NOT_AUTHORIZED");
                    break;
                default:
                    Serial.println("Unknown reason");
                    break;
            }
        }

        // Schedule reconnect attempt
        reconnectTimer = millis();
        reconnectAttempts++;

        // Implement exponential backoff for reconnection attempts
        unsigned long delayTime = min(30000, 1000 * pow(2, reconnectAttempts));

        if (enableDebug)
        {
            Serial.print("Scheduling reconnect in ");
            Serial.print(delayTime);
            Serial.println(" ms");
        }

        // Schedule reconnect after delay
        reconnectTimer = millis() + delayTime;
    });

    // Set up message received handler
    mqttClient.onMessage([](char* topic, char* payload, AsyncMqttClientMessageProperties properties, size_t len, size_t index, size_t total) {
        if (enableDebug)
        {
            Serial.print("Received message on topic: ");
            Serial.println(topic);
        }

        // Parse JSON payload
        DynamicJsonDocument doc(1024);
        DeserializationError error = deserializeJson(doc, payload, len);

        if (error)
        {
            if (enableDebug)
            {
                Serial.print("JSON parsing failed: ");
                Serial.println(error.c_str());
            }
            return;
        }

        // Process different message types based on topic
        String topicStr = String(topic);

        if (topicStr.startsWith("audio/control/"))
        {
            // Handle audio channel control commands
            String command = doc["command"] | "";
            int channelId = doc["channel"] | -1;

            if (command == "play")
            {
                // Play audio on specific channel
                if (channelId >= 0)
                {
                    playAudioChannel(channelId);
                }
            }
            else if (command == "stop")
            {
                // Stop audio on specific channel
                if (channelId >= 0)
                {
                    stopAudioChannel(channelId);
                }
            }
            else if (command == "volume")
            {
                // Set volume level
                int volume = doc["level"] | 50;
                setAudioVolume(volume);
            }
        }
        else if (topicStr.startsWith("session/updates/"))
        {
            // Handle session management updates
            String action = doc["action"] | "";

            if (action == "update")
            {
                // Update session data
                updateSessionData(doc);
            }
            else if (action == "terminate")
            {
                // Terminate current session
                terminateSession();
            }
        }
    });

    // Set up authentication credentials
    mqttClient.setCredentials(mqttUsername, mqttPassword);

    // Set keepalive interval
    mqttClient.setKeepAlive(60);

    // Set clean session flag
    mqttClient.setCleanSession(true);

    // Connect to MQTT broker
    if (enableDebug)
    {
        Serial.print("Connecting to MQTT broker at ");
        Serial.print(mqttBrokerEndpoint);
        Serial.print(":");
        Serial.println(mqttPort);
    }

    mqttClient.connect();

    // Return success status
    return true;
}

bool SendAudio(std::unique_ptr<AudioStreamPacket> packet) {
    // Validate input
    if (!packet) {
        return false;
    }

    // Thread-safe access to UDP channel using mutex
    static std::mutex udp_mutex;
    std::lock_guard<std::mutex> lock(udp_mutex);

    try {
        // Prepare encryption parameters
        // Create nonce from packet size, timestamp, and sequence number
        uint32_t packet_size = packet->payload.size();
        uint64_t timestamp = std::chrono::duration_cast<std::chrono::milliseconds>(
            std::chrono::high_resolution_clock::now().time_since_epoch()).count();
        uint32_t sequence_number = packet->sequence_number;

        // Construct nonce (12 bytes for AES-CTR)
        std::array<uint8_t, 12> nonce;
        std::memcpy(nonce.data(), &packet_size, sizeof(packet_size));
        std::memcpy(nonce.data() + 4, &timestamp, sizeof(timestamp));
        std::memcpy(nonce.data() + 12 - sizeof(sequence_number), &sequence_number, sizeof(sequence_number));

        // Encrypt payload using AES-CTR mode
        // Assuming we have access to AES-CTR encryption function
        std::vector<uint8_t> encrypted_payload = aes_ctr_encrypt(
            packet->payload, 
            get_encryption_key(),  // Function to retrieve current encryption key
            nonce
        );

        // Create UDP packet with encrypted payload
        std::vector<uint8_t> udp_packet;
        // Add header information (size, timestamp, sequence number)
        udp_packet.resize(sizeof(uint32_t) * 3 + encrypted_payload.size());

        uint32_t* header = reinterpret_cast<uint32_t*>(udp_packet.data());
        header[0] = packet_size;                    // Original packet size
        header[1] = static_cast<uint32_t>(timestamp); // Timestamp
        header[2] = sequence_number;                // Sequence number

        // Copy encrypted payload
        std::memcpy(udp_packet.data() + sizeof(uint32_t) * 3, 
                   encrypted_payload.data(), 
                   encrypted_payload.size());

        // Transmit over UDP
        // Assuming we have a UDP socket object available
        static std::unique_ptr<UDPSocket> udp_socket = create_udp_socket();

        if (!udp_socket) {
            return false;
        }

        // Send the packet
        bool success = udp_socket->send_to(
            udp_packet,
            get_destination_address(),  // Function to get destination address
            get_destination_port()      // Function to get destination port
        );

        return success;

    } catch (const std::exception& e) {
        // Handle any encryption or network errors
        return false;
    } catch (...) {
        // Handle any other unexpected errors
        return false;
    }
}

bool MqttProtocol::OpenAudioChannel() {
    // Step 1: Connect to MQTT server
    if (!ConnectToMqttServer()) {
        return false;
    }

    // Step 2: Send hello message
    if (!SendHelloMessage()) {
        DisconnectFromMqttServer();
        return false;
    }

    // Step 3: Wait for server response with timeout
    const int timeoutSeconds = 5;
    const auto startTime = std::chrono::steady_clock::now();

    bool serverResponseReceived = false;
    while (!serverResponseReceived) {
        auto currentTime = std::chrono::steady_clock::now();
        auto elapsedSeconds = std::chrono::duration_cast<std::chrono::seconds>(currentTime - startTime).count();

        if (elapsedSeconds > timeoutSeconds) {
            DisconnectFromMqttServer();
            return false;
        }

        // Check for server response
        if (CheckForServerResponse()) {
            serverResponseReceived = true;
            break;
        }

        // Small delay to prevent busy waiting
        std::this_thread::sleep_for(std::chrono::milliseconds(100));
    }

    // Step 4: Validate server response
    if (!ValidateServerResponse()) {
        DisconnectFromMqttServer();
        return false;
    }

    // Step 5: Establish UDP connection for audio packets
    if (!EstablishUdpConnection()) {
        DisconnectFromMqttServer();
        return false;
    }

    // Step 6: Set up audio packet processing
    if (!SetupAudioProcessing()) {
        CleanupAudioChannel();
        return false;
    }

    // Step 7: Start listening for audio packets
    m_audioThread = std::thread(&MqttProtocol::ProcessAudioPackets, this);

    // Step 8: Mark channel as open
    m_isAudioChannelOpen = true;

    return true;
}

