int ParseServerHello(const cJSON *serverHello)
{
    // Extract server address from JSON
    const cJSON *serverAddr = cJSON_GetObjectItem(serverHello, "serverAddress");
    if (serverAddr == NULL || !cJSON_IsString(serverAddr))
    {
        return -1; // Error: Missing or invalid server address
    }

    // Extract server port from JSON
    const cJSON *serverPort = cJSON_GetObjectItem(serverHello, "serverPort");
    if (serverPort == NULL || !cJSON_IsNumber(serverPort))
    {
        return -2; // Error: Missing or invalid server port
    }

    // Extract encryption key from JSON
    const cJSON *encryptionKey = cJSON_GetObjectItem(serverHello, "encryptionKey");
    if (encryptionKey == NULL || !cJSON_IsString(encryptionKey))
    {
        return -3; // Error: Missing or invalid encryption key
    }

    // Extract nonce from JSON
    const cJSON *nonce = cJSON_GetObjectItem(serverHello, "nonce");
    if (nonce == NULL || !cJSON_IsString(nonce))
    {
        return -4; // Error: Missing or invalid nonce
    }

    // Extract sample rate from JSON
    const cJSON *sampleRate = cJSON_GetObjectItem(serverHello, "sampleRate");
    if (sampleRate == NULL || !cJSON_IsNumber(sampleRate))
    {
        return -5; // Error: Missing or invalid sample rate
    }

    // Extract frame duration from JSON
    const cJSON *frameDuration = cJSON_GetObjectItem(serverHello, "frameDuration");
    if (frameDuration == NULL || !cJSON_IsNumber(frameDuration))
    {
        return -6; // Error: Missing or invalid frame duration
    }

    // Configure UDP transport settings
    strncpy(g_serverAddress, serverAddr->valuestring, sizeof(g_serverAddress) - 1);
    g_serverAddress[sizeof(g_serverAddress) - 1] = '\0';

    g_serverPort = (uint16_t)serverPort->valuedouble;

    // Initialize AES encryption with provided key
    if (AES_SetKey((uint8_t*)encryptionKey->valuestring, strlen(encryptionKey->valuestring)) != 0)
    {
        return -7; // Error: Failed to set encryption key
    }

    // Set nonce for encryption
    if (AES_SetNonce((uint8_t*)nonce->valuestring, strlen(nonce->valuestring)) != 0)
    {
        return -8; // Error: Failed to set nonce
    }

    // Configure audio parameters
    g_sampleRate = (uint32_t)sampleRate->valuedouble;
    g_frameDuration = (uint32_t)frameDuration->valuedouble;

    // Signal that server hello has been successfully processed
    g_serverHelloProcessed = 1;

    // Additional configuration for UDP socket if needed
    // This would typically involve setting up the socket with the extracted parameters

    return 0; // Success
}

int SendAudio(std::unique_ptr<AudioStreamPacket> packet) {
    // Check if WebSocket connection is established
    if (!websocket_connection_ || !websocket_connection_->IsOpen()) {
        return -1; // Connection error
    }

    // Validate input packet
    if (!packet) {
        return -2; // Invalid packet
    }

    // Prepare packet header based on protocol version
    std::vector<uint8_t> header;
    uint32_t payload_size = packet->data.size();

    switch (protocol_version_) {
        case 2: {
            // Protocol v2: 4-byte timestamp + 4-byte payload size
            uint32_t timestamp = static_cast<uint32_t>(std::chrono::duration_cast<std::chrono::milliseconds>(
                std::chrono::high_resolution_clock::now().time_since_epoch()).count());

            header.resize(8);
            memcpy(header.data(), &timestamp, sizeof(timestamp));
            memcpy(header.data() + 4, &payload_size, sizeof(payload_size));
            break;
        }
        case 3: {
            // Protocol v3: 8-byte timestamp + 4-byte payload size
            auto now = std::chrono::high_resolution_clock::now();
            uint64_t timestamp = static_cast<uint64_t>(std::chrono::duration_cast<std::chrono::nanoseconds>(
                now.time_since_epoch()).count());

            header.resize(12);
            memcpy(header.data(), &timestamp, sizeof(timestamp));
            memcpy(header.data() + 8, &payload_size, sizeof(payload_size));
            break;
        }
        default: {
            // Raw payload format: no header, just payload
            header.clear();
            break;
        }
    }

    // Construct full packet
    std::vector<uint8_t> full_packet;
    if (!header.empty()) {
        full_packet.insert(full_packet.end(), header.begin(), header.end());
    }
    full_packet.insert(full_packet.end(), packet->data.begin(), packet->data.end());

    // Send over WebSocket
    try {
        websocket_connection_->SendBinary(full_packet.data(), full_packet.size());

        // Verify successful transmission
        if (websocket_connection_->GetLastErrorCode() != 0) {
            return -3; // Transmission error
        }

        return 0; // Success
    } catch (const std::exception& e) {
        return -4; // Exception during send
    }
}

bool WebsocketProtocol::OpenAudioChannel() {
    // Configure authentication headers
    std::map<std::string, std::string> headers;
    headers["Authorization"] = "Bearer " + m_authToken;
    headers["Content-Type"] = "application/json";

    // Set protocol version
    std::string protocolVersion = "v3"; // Default to latest version

    // Configure device identifiers
    std::string deviceId = m_deviceId;
    std::string sessionId = GenerateSessionId();

    // Create WebSocket connection parameters
    WebSocketConfig config;
    config.url = m_websocketUrl + "/audio/stream";
    config.headers = headers;
    config.protocol = protocolVersion;
    config.deviceId = deviceId;
    config.sessionId = sessionId;

    // Attempt to establish WebSocket connection
    if (!m_websocketClient->Connect(config)) {
        return false;
    }

    // Set up data handler for incoming binary audio packets
    auto dataHandler = [this](const std::vector<uint8_t>& packetData) {
        ProcessAudioPacket(packetData);
    };

    m_websocketClient->SetDataHandler(dataHandler);

    // Configure protocol-specific parsing based on version
    if (protocolVersion == "v2") {
        m_protocolVersion = ProtocolVersion::V2;
        m_byteOrder = ByteOrder::LittleEndian;
    } else if (protocolVersion == "v3") {
        m_protocolVersion = ProtocolVersion::V3;
        m_byteOrder = ByteOrder::BigEndian;
    } else {
        // Unsupported protocol version
        m_websocketClient->Disconnect();
        return false;
    }

    // Validate that all required components are properly initialized
    if (m_websocketClient == nullptr || !m_websocketClient->IsConnected()) {
        return false;
    }

    // Set channel state to open
    m_channelState = ChannelState::Open;

    // Notify listeners that audio channel is open
    OnAudioChannelOpened();

    return true;
}

