int ParseServerHello(const cJSON *serverHello)
{
    // Validate input parameter
    if (serverHello == NULL)
    {
        return -1; // Error: invalid input
    }

    // Extract session ID from server hello message
    const cJSON *sessionId = cJSON_GetObjectItem(serverHello, "session_id");
    if (sessionId == NULL || !cJSON_IsString(sessionId))
    {
        return -2; // Error: missing or invalid session ID
    }

    // Store session ID in global or static variable
    strncpy(g_sessionId, sessionId->valuestring, sizeof(g_sessionId) - 1);
    g_sessionId[sizeof(g_sessionId) - 1] = '\0'; // Ensure null termination

    // Extract transport type
    const cJSON *transportType = cJSON_GetObjectItem(serverHello, "transport_type");
    if (transportType == NULL || !cJSON_IsString(transportType))
    {
        return -3; // Error: missing or invalid transport type
    }

    // Validate transport type (assuming only "websocket" is supported)
    if (strcmp(transportType->valuestring, "websocket") != 0)
    {
        return -4; // Error: unsupported transport type
    }

    // Extract audio configuration parameters
    const cJSON *audioConfig = cJSON_GetObjectItem(serverHello, "audio_config");
    if (audioConfig == NULL || !cJSON_IsObject(audioConfig))
    {
        return -5; // Error: missing or invalid audio configuration
    }

    // Extract sample rate
    const cJSON *sampleRate = cJSON_GetObjectItem(audioConfig, "sample_rate");
    if (sampleRate == NULL || !cJSON_IsNumber(sampleRate))
    {
        return -6; // Error: missing or invalid sample rate
    }

    g_audioSampleRate = (int)sampleRate->valuedouble;

    // Extract frame duration
    const cJSON *frameDuration = cJSON_GetObjectItem(audioConfig, "frame_duration_ms");
    if (frameDuration == NULL || !cJSON_IsNumber(frameDuration))
    {
        return -7; // Error: missing or invalid frame duration
    }

    g_frameDurationMs = (int)frameDuration->valuedouble;

    // Set event flag to signal successful parsing and readiness
    // Assuming there's an event flag mechanism available
    SetWebSocketReadyFlag();

    // Additional validation for reasonable audio parameters
    if (g_audioSampleRate <= 0 || g_audioSampleRate > 192000)
    {
        return -8; // Error: invalid sample rate range
    }

    if (g_frameDurationMs <= 0 || g_frameDurationMs > 1000)
    {
        return -9; // Error: invalid frame duration range
    }

    // All validations passed, return success
    return 0; // Success
}
